  // Customer: Accept quote for remote request
  app.patch("/api/customer/remote-requests/:id/accept-quote", requireRole("customer"), async (req, res) => {
    try {
      if (!req.user) return res.status(401).send("Unauthorized");
      
      const request = await storage.getRemoteRepairRequest(req.params.id);
      if (!request) return res.status(404).send("Richiesta non trovata");
      
      if (request.customerId !== req.user.id) {
        return res.status(403).send("Accesso non autorizzato");
      }
      
      if (request.status !== 'quoted') {
        return res.status(400).send("Non c'è un preventivo da accettare");
      }
      
      const { paymentMethod } = req.body;
      
      if (!paymentMethod || !['online_stripe', 'online_paypal', 'in_store'].includes(paymentMethod)) {
        return res.status(400).send("Metodo di pagamento non valido");
      }
      
      const repairCenter = await storage.getRepairCenter((req.user as any).repairCenterId);
      
      if (paymentMethod === 'in_store') {
        const updated = await storage.updateRemoteRepairRequest(req.params.id, {
          status: 'awaiting_shipment',
          paymentMethod: 'in_store',
          paymentStatus: 'pending',
          quoteResponseAt: new Date(),
          customerAddress: repairCenter?.address || request.customerAddress || null,
          customerCity: repairCenter?.city || request.customerCity || null,
          customerCap: repairCenter?.cap || request.customerCap || null,
          customerProvince: repairCenter?.provincia || request.customerProvince || null,
        });
        
        const devices = await storage.listRemoteRepairRequestDevices(req.params.id);
        for (const d of devices) {
          await storage.updateRemoteRepairRequestDevice(d.id, { status: 'awaiting_shipment' });
        }
        
        setActivityEntity(res, { type: 'remote_repair_requests', id: updated.id });

        // Generate invoice for in-store payment
        try {
          const customerIs = await storage.getUser(request.customerId);
          const centerUserIs = request.assignedCenterId ? await storage.getUser(request.assignedCenterId) : null;
          const rcEntityIs = centerUserIs?.repairCenterId ? await storage.getRepairCenter(centerUserIs.repairCenterId) : null;
          
          const quoteAmountIs = request.quoteAmount || 0;
          if (quoteAmountIs <= 0) throw new Error('No quote amount');
          
          // Check for existing invoice (idempotency)
          const existingInvoicesIs = await storage.listInvoices({ customerId: request.customerId });
          const alreadyInvoicedIs = existingInvoicesIs.find((inv: any) => inv.remoteRepairRequestId === request.id);
          if (alreadyInvoicedIs) throw new Error('Invoice already exists');
          
          const vatRateIs = 22;
          const taxAmountIs = Math.round(quoteAmountIs * vatRateIs / (100 + vatRateIs));
          const netAmountIs = quoteAmountIs - taxAmountIs;
          
          let invoiceNumberIs: string;
          if (rcEntityIs?.id) {
            invoiceNumberIs = await storage.generateInvoiceNumber(rcEntityIs.id);
          } else if (request.resellerId) {
            invoiceNumberIs = await storage.generateResellerInvoiceNumber(request.resellerId);
          } else {
            invoiceNumberIs = await storage.generateAdminInvoiceNumber();
          }
          
          await storage.createInvoice({
            invoiceNumber: invoiceNumberIs,
            remoteRepairRequestId: request.id,
            customerId: request.customerId,
            repairCenterId: rcEntityIs?.id || null,
            resellerId: request.resellerId || null,
            source: 'remote_repair' as any,
            amount: netAmountIs,
            tax: taxAmountIs,
            vatRate: vatRateIs,
            total: quoteAmountIs,
            paymentStatus: 'pending',
            paymentMethod: 'in_store',
            notes: `Fattura per richiesta remota #${request.requestNumber}`,
          } as any);
        } catch (invoiceErr) {
          console.error("Error creating invoice for remote request:", invoiceErr);
        }

        if (request.assignedCenterId) {
          await storage.createNotification({
            userId: request.assignedCenterId,
            type: "system",
            title: "Preventivo accettato",
            message: `Il cliente ha accettato il preventivo per la richiesta #${request.requestNumber} (pagamento in negozio)`,
            data: JSON.stringify({ remoteRequestId: request.id })
          });
          broadcastNotification(request.assignedCenterId, {
            type: "remote_quote_accepted",
            title: "Preventivo accettato",
            message: `Il cliente ha accettato il preventivo per la richiesta #${request.requestNumber}`,
            requestId: request.id
          });
        }

        return res.json(updated);
      }
      
      const updated = await storage.updateRemoteRepairRequest(req.params.id, {
        status: 'quote_accepted',
        paymentMethod,
        paymentStatus: 'pending',
        quoteResponseAt: new Date(),
      });
      
      const devices = await storage.listRemoteRepairRequestDevices(req.params.id);
      for (const d of devices) {
        await storage.updateRemoteRepairRequestDevice(d.id, { status: 'quote_accepted' });
      }
      
      setActivityEntity(res, { type: 'remote_repair_requests', id: updated.id });

      if (request.assignedCenterId) {
        await storage.createNotification({
          userId: request.assignedCenterId,
          type: "system",
          title: "Preventivo accettato",
          message: `Il cliente ha accettato il preventivo per la richiesta #${request.requestNumber} (pagamento online)`,
          data: JSON.stringify({ remoteRequestId: request.id })
        });
        broadcastNotification(request.assignedCenterId, {
          type: "remote_quote_accepted",
          title: "Preventivo accettato",
          message: `Il cliente ha accettato il preventivo per la richiesta #${request.requestNumber}`,
          requestId: request.id
        });
      }

      res.json(updated);
    } catch (error: any) {
      console.error("Accept quote error:", error);
      res.status(500).send(error.message);
    }
  });

