  // Customer: get available payment methods (from repair center or reseller with fallback)
  app.get("/api/customer/payment-methods", requireRole("customer"), async (req, res) => {
    try {
      if (!req.user) return res.status(401).send("Unauthorized");
      
      const resellerId = req.user.resellerId;
      const repairCenterId = req.user.repairCenterId;
      
      if (!resellerId) {
        return res.status(400).send("Nessun rivenditore associato");
      }
      
      let effectiveConfig = null;
      let configSource = "none";
      
      // If customer is associated with a repair center, try RC config first
      if (repairCenterId) {
        const rcConfig = await storage.getPaymentConfiguration("repair_center", repairCenterId);
        
        if (rcConfig && !rcConfig.useParentConfig) {
          effectiveConfig = rcConfig;
          configSource = "repair_center";
        }
      }
      
      // Fallback to reseller config
      if (!effectiveConfig) {
        effectiveConfig = await storage.getPaymentConfiguration("reseller", resellerId);
        configSource = "reseller";
      }
      
      // Build available methods list
      const methods: {
        id: string;
        name: string;
        enabled: boolean;
        details?: any;
      }[] = [];
      
      // In-person is always available
      methods.push({
        id: "in_person",
        name: "Pagamento di persona",
        enabled: true
      });
      
      // Bank transfer
      if (effectiveConfig?.bankTransferEnabled) {
        methods.push({
          id: "bank_transfer",
          name: "Bonifico bancario",
          enabled: true,
          details: {
            iban: effectiveConfig.iban,
            accountHolder: effectiveConfig.accountHolder,
            bankName: effectiveConfig.bankName,
            bic: effectiveConfig.bic
          }
        });
      }
      
      // Stripe
      if (effectiveConfig?.stripeEnabled && effectiveConfig?.stripePublishableKey) {
        methods.push({
          id: "card",
          name: "Carta di credito/debito",
          enabled: true,
          details: {
            publishableKey: effectiveConfig.stripePublishableKey
          }
        });
      }
      
      // PayPal
      if (effectiveConfig?.paypalEnabled && effectiveConfig?.paypalClientId) {
        methods.push({
          id: "paypal",
          name: "PayPal",
          enabled: true,
          details: {
            clientId: effectiveConfig.paypalClientId
          }
        });
      }
      
      
      res.json({
        methods,
        configSource
      });
    } catch (error: any) {
      console.error("Service order creation error:", error);
      res.status(500).send(error.message);
    }
  });

  // Customer: get service catalog from their reseller
  app.get("/api/customer/service-catalog", requireRole("customer"), async (req, res) => {
    try {
      if (!req.user) return res.status(401).send("Unauthorized");
      
      const resellerId = req.user.resellerId;
      if (!resellerId) {
        return res.status(400).send("Nessun rivenditore associato");
      }
      
      // Get reseller's repair centers for filtering
      const repairCenters = await storage.listRepairCenters();
      const resellerRepairCenters = repairCenters.filter(rc => rc.resellerId === resellerId);
      
      const items = await storage.listServiceItems();
      // Include: global items + reseller items + items from reseller's repair centers
      const activeItems = items.filter(item => 
        item.isActive && (
          (!item.resellerId && !item.repairCenterId) || // Global items (admin)
          item.resellerId === resellerId || // Reseller's own items
          resellerRepairCenters.some(rc => rc.id === item.repairCenterId) // Repair center items
        )
      );
      
      // Cerca listino prezzi per clienti del reseller
      const priceList = await storage.getPriceListForTarget(resellerId, "customer");
      
      const itemsWithPrices = await Promise.all(activeItems.map(async (item) => {
        let effectivePriceCents = item.defaultPriceCents;
        let priceSource = "base";
        
        // Se esiste un listino per clienti, cerca il prezzo lì
        if (priceList) {
          const priceListItem = await storage.getPriceForItem(priceList.id, undefined, item.id);
          if (priceListItem && priceListItem.isActive) {
            effectivePriceCents = priceListItem.priceCents;
            priceSource = "price_list";
          }
        }
        
        // Fallback al vecchio sistema se non trovato nel listino
        if (priceSource === "base") {
          const oldPrice = await storage.getEffectiveServicePrice(item.id, resellerId, undefined);
          if (oldPrice.source !== "base") {
            effectivePriceCents = oldPrice.priceCents;
            priceSource = oldPrice.source;
          }
        }
        
        return {
          ...item,
          effectivePriceCents,
          effectiveLaborMinutes: item.defaultLaborMinutes,
          priceSource
        };
      }));
      
      res.json(itemsWithPrices);
    } catch (error: any) {
      console.error("Service order creation error:", error);
      res.status(500).send(error.message);
    }
  });
  
