  // Customer: create service order
  app.post("/api/customer/service-orders", requireRole("customer"), async (req, res) => {
    try {
      if (!req.user) return res.status(401).send("Unauthorized");
      
      const resellerId = req.user.resellerId;
      if (!resellerId) {
        return res.status(400).send("Nessun rivenditore associato");
      }
      
      const { serviceItemId, deviceType, deviceModelId, brand, model, imei, serial, issueDescription, customerNotes, paymentMethod } = req.body;
      
      if (!serviceItemId) {
        return res.status(400).send("Servizio richiesto");
      }
      
      if (!paymentMethod || !['in_person', 'bank_transfer', 'card', 'paypal'].includes(paymentMethod)) {
        return res.status(400).send("Metodo di pagamento non valido");
      }
      
      const serviceItem = await storage.getServiceItem(serviceItemId);
      if (!serviceItem) {
        return res.status(404).send("Servizio non trovato");
      }
      
      // Verify service item is accessible to this reseller (global or created by reseller)
      if (serviceItem.createdBy !== null && serviceItem.createdBy !== resellerId) {
        return res.status(403).send("Servizio non disponibile");
      }
      
      const effectivePrice = await storage.getEffectiveServicePrice(serviceItemId, resellerId, undefined);
      
      // Auto-approval for automatic payment methods (card/paypal)
      const isAutoPayment = paymentMethod === 'card' || paymentMethod === 'paypal';
      const customerRepairCenterId = req.user.repairCenterId || undefined;
      
      const order = await storage.createServiceOrder({
        customerId: req.user.id,
        resellerId,
        repairCenterId: customerRepairCenterId,
        serviceItemId,
        priceCents: effectivePrice.priceCents,
        deviceType,
        deviceModelId,
        brand,
        model,
        imei,
        serial,
        issueDescription,
        customerNotes,
        paymentMethod,
        status: isAutoPayment ? 'accepted' : 'pending',
        paymentStatus: isAutoPayment ? 'paid' : 'pending'
      });
      
      // Notify reseller about new service order
      await storage.createNotification({
        userId: resellerId,
        type: "system",
        title: "Nuovo ordine servizio",
        message: `${req.user.fullName} ha richiesto: ${serviceItem.name}`,
        data: JSON.stringify({ serviceOrderId: order.id, customerId: req.user.id })
      });
      broadcastNotification(resellerId, {
        type: "new_service_order",
        title: "Nuovo ordine servizio",
        message: `${req.user.fullName} ha richiesto: ${serviceItem.name}`,
        orderId: order.id
      });
      
      // Notify repair center if customer has one assigned
      if (customerRepairCenterId) {
        const repairCenter = await storage.getRepairCenter(customerRepairCenterId);
        if (repairCenter && repairCenter.userId) {
          await storage.createNotification({
            userId: repairCenter.userId,
            type: "system",
            title: "Nuovo ordine servizio",
            message: `${req.user.fullName} ha richiesto: ${serviceItem.name}`,
            data: JSON.stringify({ serviceOrderId: order.id, customerId: req.user.id })
          });
          broadcastNotification(repairCenter.userId, {
            type: "new_service_order",
            title: "Nuovo ordine servizio",
            message: `${req.user.fullName} ha richiesto: ${serviceItem.name}`,
            orderId: order.id
          });
        }
      }
      
      setActivityEntity(res, { type: 'service_orders', id: order.id });
      res.status(201).json(order);
    } catch (error: any) {
      console.error("Service order creation error:", error);
      res.status(500).send(error.message);
    }
  });
  
