  // ============ TICKETS ============
  
  // List tickets with role-based filtering
  app.get("/api/tickets", requireAuth, async (req, res) => {
    try {
      if (!req.user) return res.status(401).send("Unauthorized");
      
      const filters: { customerId?: string; assignedTo?: string; status?: string; resellerId?: string } = {};
      
      // Role-based filtering
      if (req.user.role === 'customer') {
        // Customers see only their own tickets
        filters.customerId = req.user.id;
      } else if (req.user.role === 'reseller') {
        // Resellers see tickets from their customers
        filters.resellerId = req.user.id;
      } else if ((req.user.role === 'repair_center' || req.user.role === 'repair_center_staff') && req.user.repairCenterId) {
        // Repair centers see assigned tickets
        filters.assignedTo = req.user.id;
      } else if (req.user.role === 'reseller_staff') {
        // Check permission
        const hasPermission = await storage.checkStaffPermission(req.user.id, 'tickets', 'read');
        if (!hasPermission) {
          return res.status(403).send("Non hai i permessi per visualizzare i ticket");
        }
        // Staff sees tickets of their parent reseller
        if (req.user.resellerId) {
          filters.assignedTo = req.user.resellerId;
        }
      }
      // Admin sees all tickets (no filter)
      
      // Apply status filter if provided
      if (req.query.status && typeof req.query.status === 'string') {
        filters.status = req.query.status;
      }
      
      const tickets = await storage.listTickets(filters);
      res.json(tickets);
    } catch (error: any) {
      console.error("Service order creation error:", error);
      res.status(500).send(error.message);
    }
  });
  
  // Get single ticket details
  app.get("/api/tickets/:id", requireAuth, async (req, res) => {
    try {
      if (!req.user) return res.status(401).send("Unauthorized");
      
      const ticket = await storage.getTicket(req.params.id);
      if (!ticket) return res.status(404).send("Ticket not found");
      
      // Check access based on role and ticket type
      let hasAccess = false;
      
      if (req.user.role === 'admin' || req.user.role === 'admin_staff') {
        // Admin can see all tickets
        hasAccess = true;
      } else if (req.user.role === 'reseller_staff') {
        // Check permission first
        const hasPermission = await storage.checkStaffPermission(req.user.id, 'tickets', 'read');
        if (hasPermission && req.user.resellerId) {
          // Check if ticket belongs to parent reseller
          if (ticket.initiatorId === req.user.resellerId || 
              (ticket.targetType === 'reseller' && ticket.targetId === req.user.resellerId)) {
            hasAccess = true;
          }
        }
      } else if (ticket.ticketType === 'internal') {
        // For internal tickets, check if user is initiator or target
        // User is initiator
        if (ticket.initiatorId === req.user.id) {
          hasAccess = true;
        }
        // User is targeted reseller
        else if (ticket.targetType === 'reseller' && ticket.targetId === req.user.id) {
          hasAccess = true;
        }
        // User is repair_center role - targetId matches their user ID
        else if (ticket.targetType === 'repair_center' && ticket.targetId === req.user.id) {
          hasAccess = true;
        }
      } else {
        // For support tickets (customer→admin) - also visible to customer's reseller
        if (ticket.customerId === req.user.id || ticket.assignedTo === req.user.id) {
          hasAccess = true;
        } else if (req.user.role === 'reseller' || req.user.role === 'reseller_staff') {
          // Check if ticket belongs to a customer of this reseller
          const customer = await storage.getUser(ticket.customerId);
          const resellerId = req.user.role === 'reseller_staff' ? (req.user as any).resellerId : req.user.id;
          if (customer && customer.resellerId === resellerId) {
            hasAccess = true;
          }
        }
      }
      
      if (!hasAccess) return res.status(403).send("Accesso negato");
      
      res.json(ticket);
    } catch (error: any) {
      console.error("Service order creation error:", error);
      res.status(500).send(error.message);
    }
  });
  
