  // Create internal ticket (for business entities)
  app.post("/api/internal-tickets", requireAuth, async (req, res) => {
    try {
      if (!req.user) return res.status(401).send("Unauthorized");
      
      // Only business entities can create internal tickets
      if (!['admin', 'admin_staff', 'reseller', 'reseller_staff', 'repair_center'].includes(req.user.role)) {
        return res.status(403).send("Solo rivenditori, centri riparazione e admin possono creare ticket interni");
      }
      
      const { subject, description, priority, targetType, targetId } = req.body;
      
      // Validate required fields
      if (!subject || !description) {
        return res.status(400).send("Oggetto e descrizione sono obbligatori");
      }
      
      // Validate target type based on user role
      const validTargets = getValidTargetTypes(req.user.role);
      if (!targetType || !validTargets.includes(targetType)) {
        return res.status(400).send("Tipo destinatario non valido");
      }
      
      // For non-admin targets, targetId is required
      if (targetType !== 'admin' && !targetId) {
        return res.status(400).send("ID destinatario obbligatorio");
      }
      
      const ticket = await storage.createTicket({
        customerId: req.user.id, // For backward compatibility
        subject,
        description,
        priority: priority || 'medium',
        status: 'open',
        ticketType: 'internal',
        initiatorId: req.user.id,
        initiatorRole: req.user.role,
        targetType,
        targetId: targetType === 'admin' ? null : targetId,
      });
      
      setActivityEntity(res, { type: 'ticket', id: ticket.id });
      
      // Broadcast notification to target
      if (targetType === 'admin') {
        // Notify all admins
        const allUsers = await storage.listUsers();
      const admin = allUsers.find(u => u.role === 'admin');
        for (const admin of admins) {
          broadcastNotification(admin.id, {
            type: 'new_internal_ticket',
            ticketId: ticket.id,
            from: req.user.username,
          });
        }
      } else if (targetId) {
        broadcastNotification(targetId, {
          type: 'new_internal_ticket',
          ticketId: ticket.id,
          from: req.user.username,
        });
      }
      
      res.json(ticket);
    } catch (error: any) {
      console.error("Service order creation error:", error);
      res.status(400).send(error.message);
    }
  });
  
  // Helper function to determine valid target types based on user role
  function getValidTargetTypes(role: string): string[] {
    switch (role) {
      case 'admin':
      case 'admin_staff':
        return ['reseller', 'repair_center'];
      case 'reseller':
      case 'reseller_staff':
        return ['admin', 'repair_center'];
      case 'repair_center':
        return ['admin', 'reseller'];
      default:
        return [];
    }
  }
  
  // Update ticket status (admin, assigned users, and resellers for their customers)
  app.patch("/api/tickets/:id/status", requireAuth, async (req, res) => {
    try {
      if (!req.user) return res.status(401).send("Unauthorized");
      
      const ticket = await storage.getTicket(req.params.id);
      if (!ticket) return res.status(404).send("Ticket not found");
      
      const { status } = req.body;
      if (!status || !['open', 'in_progress', 'closed'].includes(status)) {
        return res.status(400).send("Invalid status");
      }
      
      // Check permissions based on role
      let canUpdate = false;
      
      // Admin can do anything
      if (req.user.role === 'admin' || req.user.role === 'admin_staff') {
        canUpdate = true;
      }
      // Reseller/reseller_staff permissions
      else if (req.user.role === 'reseller' || req.user.role === 'reseller_staff') {
        const resellerId = req.user.role === 'reseller_staff' ? (req.user as any).resellerId : req.user.id;
        
        // Internal tickets: initiator can update status
        if (ticket.ticketType === 'internal' && ticket.initiatorId === resellerId) {
          canUpdate = true;
        }
        // Support tickets: reseller can close tickets from their customers
        else if (ticket.ticketType === 'support') {
          const customer = await storage.getUser(ticket.customerId);
          if (customer && customer.resellerId === resellerId) {
            if (status === 'closed') {
              canUpdate = true;
            } else {
              return res.status(403).send("I rivenditori possono solo chiudere i ticket");
            }
          }
        }
        // Also allow if assigned to the reseller
        if (!canUpdate && ticket.assignedTo === req.user.id) {
          canUpdate = true;
        }
      }
      // Repair center: can update internal tickets targeted to them or where they are initiator
      else if (req.user.role === 'repair_center' || req.user.role === 'repair_center_staff') {
        if (ticket.ticketType === 'internal') {
          const rcId = req.user.role === 'repair_center_staff' ? req.user.repairCenterId : 
            (await storage.getUser(req.user.id))?.repairCenterId;
          if (ticket.initiatorId === req.user.id || (ticket.targetType === 'repair_center' && ticket.targetId === rcId)) {
            canUpdate = true;
          }
        }
        if (!canUpdate && ticket.assignedTo === req.user.id) {
          canUpdate = true;
        }
      }
      // Any assigned user can update status
      else if (ticket.assignedTo === req.user.id) {
        canUpdate = true;
      }
      // Customer can close their own tickets
      else if (req.user.role === 'customer' && ticket.customerId === req.user.id && status === 'closed') {
        canUpdate = true;
      }
      
      if (!canUpdate) return res.status(403).send("Forbidden");
      
      const updatedTicket = await storage.updateTicketStatus(req.params.id, status);
      setActivityEntity(res, { type: 'ticket', id: updatedTicket.id });
      
      const statusLabels: Record<string, string> = { open: "Aperto", in_progress: "In lavorazione", closed: "Chiuso" };
      const statusLabel = statusLabels[updatedTicket.status] || updatedTicket.status;

      // Notify customer about ticket status change (with in-app + push)
      await storage.createNotification({
        userId: updatedTicket.customerId,
        type: "system",
        title: `Ticket ${statusLabel}`,
        message: `Il tuo ticket #${updatedTicket.id.substring(0, 8)} è stato aggiornato a: ${statusLabel}`,
        data: JSON.stringify({ ticketId: updatedTicket.id, status: updatedTicket.status }),
      });
      broadcastNotification(updatedTicket.customerId, { 
        type: 'ticket_status_changed', 
        title: `Ticket ${statusLabel}`,
        message: `Il tuo ticket è stato aggiornato a: ${statusLabel}`,
        ticketId: updatedTicket.id,
        status: updatedTicket.status 
      });
      
      if (updatedTicket.assignedTo) {
        await storage.createNotification({
          userId: updatedTicket.assignedTo,
          type: "system",
          title: `Ticket ${statusLabel}`,
          message: `Il ticket #${updatedTicket.id.substring(0, 8)} è stato aggiornato a: ${statusLabel}`,
          data: JSON.stringify({ ticketId: updatedTicket.id, status: updatedTicket.status }),
        });
        broadcastNotification(updatedTicket.assignedTo, { 
          type: 'ticket_status_changed', 
          title: `Ticket ${statusLabel}`,
          message: `Il ticket è stato aggiornato a: ${statusLabel}`,
          ticketId: updatedTicket.id,
          status: updatedTicket.status 
        });
      }
      
      res.json(updatedTicket);
    } catch (error: any) {
      console.error("Service order creation error:", error);
      res.status(500).send(error.message);
    }
  });
  
  // Assign ticket (admin only)
  app.patch("/api/tickets/:id/assign", requireAuth, async (req, res) => {
    try {
      if (!req.user) return res.status(401).send("Unauthorized");
      
      if (req.user.role !== 'admin') {
        return res.status(403).send("Only admins can assign tickets");
      }
      
      const ticket = await storage.getTicket(req.params.id);
      if (!ticket) return res.status(404).send("Ticket not found");
      
      const { assignedTo } = req.body;
      
      // Validate assignedTo user exists if provided
      if (assignedTo) {
        const assignedUser = await storage.getUser(assignedTo);
        if (!assignedUser) return res.status(400).send("Invalid user ID");
        
        // Can only assign to reseller or repair_center staff
        if (!['reseller', 'repair_center', 'admin'].includes(assignedUser.role)) {
          return res.status(400).send("Can only assign to reseller, repair center, or admin");
        }
      }
      
      const updatedTicket = await storage.assignTicket(req.params.id, assignedTo || null);
      setActivityEntity(res, { type: 'ticket', id: updatedTicket.id });
      
      // Broadcast real-time update to customer, old assignee, and new assignee
      broadcastNotification(updatedTicket.customerId, { 
        type: 'ticket_assigned', 
        ticketId: updatedTicket.id,
        assignedTo: updatedTicket.assignedTo 
      });
      
      if (ticket.assignedTo && ticket.assignedTo !== updatedTicket.assignedTo) {
        broadcastNotification(ticket.assignedTo, { 
          type: 'ticket_assigned', 
          ticketId: updatedTicket.id,
          assignedTo: updatedTicket.assignedTo 
        });
      }
      
      if (updatedTicket.assignedTo) {
        broadcastNotification(updatedTicket.assignedTo, { 
          type: 'ticket_assigned', 
          ticketId: updatedTicket.id,
          assignedTo: updatedTicket.assignedTo 
        });
      }
      
      res.json(updatedTicket);
    } catch (error: any) {
      console.error("Service order creation error:", error);
      res.status(500).send(error.message);
    }
  });
  
