  // ============ ACCESSORIES (Accessori) ============
  
  // List accessories with specs and device compatibilities
  app.get("/api/accessories", requireAuth, async (req, res) => {
    try {
      if (!req.user) return res.status(401).send("Unauthorized");
      
      const filters: { resellerId?: string; accessoryType?: string } = {};
      let effectiveResellerId: string | null = null;
      
      if (req.user.role === 'reseller' || req.user.role === 'reseller_collaborator' || req.user.role === 'reseller_staff') {
        effectiveResellerId = (req.user.role === 'reseller_collaborator' || req.user.role === 'reseller_staff') ? req.user.resellerId : req.user.id;
        if (effectiveResellerId) filters.resellerId = effectiveResellerId;
      } else if (req.user.role !== 'admin') {
        return res.status(403).send("Access denied");
      }
      
      if (req.query.accessoryType) filters.accessoryType = req.query.accessoryType as string;
      
      const accessories = await storage.listAccessories(filters);
      
      // Add isOwn flag and device compatibilities for each accessory
      const accessoriesWithExtras = await Promise.all(accessories.map(async (accessory) => {
        const rawCompatibilities = await storage.listProductCompatibilities(accessory.id);
        const deviceCompatibilities = await Promise.all(
          rawCompatibilities.map(async (c) => {
            const brand = await storage.getDeviceBrand(c.deviceBrandId);
            const model = c.deviceModelId ? await storage.getDeviceModel(c.deviceModelId) : null;
            return {
              deviceBrandId: c.deviceBrandId,
              deviceBrandName: brand?.name || null,
              deviceModelId: c.deviceModelId,
              deviceModelName: model?.modelName || null,
            };
          })
        );
        // Get preferred supplier
        const productSuppliers = await storage.listProductSuppliers(accessory.id);
        const preferredSupplier = productSuppliers.find(ps => ps.isPreferred);
        let supplierInfo = null;
        if (preferredSupplier) {
          const supplier = await storage.getSupplier(preferredSupplier.supplierId);
          if (supplier) {
            supplierInfo = { id: supplier.id, name: supplier.name, code: supplier.code };
          }
        }
        return { 
          ...accessory, 
          isOwn: effectiveResellerId ? accessory.createdBy === effectiveResellerId : false,
          deviceCompatibilities,
          supplier: supplierInfo,
        };
      }));
      
      res.json(accessoriesWithExtras);
    } catch (error: any) {
      console.error("Service order creation error:", error);
      res.status(500).send(error.message);
    }
  });
  
