  // POST /api/repair-orders/:id/parts - Create parts order
  app.post("/api/repair-orders/:id/parts", requireAuth, async (req, res) => {
    try {
      if (!req.user) return res.status(401).send("Unauthorized");
      
      const repairOrder = await storage.getRepairOrder(req.params.id);
      if (!repairOrder) {
        return res.status(404).send("Repair order not found");
      }
      
      // Role-based access control for creating parts order
      if (req.user.role === 'admin') {
        // Admin can create parts order for any order
      } else if ((req.user.role === 'repair_center' || req.user.role === 'repair_center_staff') && req.user.repairCenterId) {
        if (repairOrder.repairCenterId !== req.user.repairCenterId) {
          return res.status(403).send("Access denied");
        }
      } else if (req.user.role === 'reseller') {
        const canManage = await canResellerManageOrder(req.user.id, repairOrder);
        if (!canManage) {
          return res.status(403).send("Access denied");
        }
      } else {
        return res.status(403).send("Only admins, repair centers and resellers can order parts");
      }
      
      // Convert expectedArrival string to Date if provided
      const expectedArrival = req.body.expectedArrival 
        ? new Date(req.body.expectedArrival) 
        : undefined;
      
      // If ordering an existing product and user is repair_center, also create a B2B order
      let b2bOrderId: string | null = null;
      if (req.body.productId && repairOrder.repairCenterId) {
        const repairCenter = await storage.getRepairCenter(repairOrder.repairCenterId);
        const product = await storage.getProduct(req.body.productId);
        
        if (repairCenter && repairCenter.resellerId && product) {
          // Create B2B order for repair center -> reseller
          // Note: orderNumber is generated automatically in createRepairCenterPurchaseOrder
          const quantity = req.body.quantity || 1;
          const unitPrice = product.costPrice || product.unitPrice || 0;
          const subtotal = unitPrice * quantity;
          
          const b2bOrder = await storage.createRepairCenterPurchaseOrder({
            repairCenterId: repairOrder.repairCenterId,
            resellerId: repairCenter.resellerId,
            status: paymentMethod === 'card' || paymentMethod === 'paypal' ? 'approved' : 'pending',
            subtotal,
            discountAmount: 0,
            shippingCost: 0,
            total: subtotal,
            paymentMethod: 'bank_transfer',
            notes: `Ordine ricambio per riparazione #${repairOrder.ticketNumber || repairOrder.id}`,
          });
          
          b2bOrderId = b2bOrder.id;
          
          // Create order item
          await storage.createRepairCenterPurchaseOrderItem({
            orderId: b2bOrder.id,
            productId: req.body.productId,
            productName: product.name,
            productSku: product.sku || null,
            quantity,
            unitPrice: unitPrice,
            totalPrice: subtotal,
          });
        }
      }
      
      const partsOrder = await storage.createPartsOrder({
        repairOrderId: req.params.id,
        productId: req.body.productId || null,
        partName: req.body.partName,
        partNumber: req.body.partNumber,
        quantity: req.body.quantity || 1,
        unitCost: req.body.unitCost,
        supplier: req.body.supplier,
        expectedArrival,
        notes: b2bOrderId ? `${req.body.notes || ''} [B2B: ${b2bOrderId}]`.trim() : req.body.notes,
        orderedBy: req.user.id,
      });
      
      // Transition status to attesa_ricambi if not already
      if (repairOrder.status === 'preventivo_accettato') {
        await storage.updateRepairOrder(req.params.id, {
          status: 'attesa_ricambi' as any,
        });
      }
      
      res.status(201).json(partsOrder);
    } catch (error: any) {
      console.error("Service order creation error:", error);
      res.status(400).send(error.message);
    }
  });

