      doc.fontSize(12).font('Helvetica-Bold').text('DIAGNOSI TECNICA', { align: 'left' });
      doc.fontSize(10).font('Helvetica');
      doc.text(diagnostics.technicalDiagnosis || 'N/A', { align: 'left' });
      doc.moveDown();
      
