  // GET /api/users/:id - Get a single user by ID
  app.get("/api/users/:id", requireAuth, async (req, res) => {
    try {
      if (!req.user) return res.status(401).send("Unauthorized");
      
      const { id } = req.params;
      const user = await storage.getUser(id);
      
      if (!user) {
        return res.status(404).send("User not found");
      }
      
      // Authorization: admin can see all, reseller can see their customers/sub-entities, user can see themselves
      const canAccess = 
        req.user.role === 'admin' ||
        req.user.id === id ||
        (req.user.role === 'reseller' && (user.resellerId === req.user.id || user.parentResellerId === req.user.id)) ||
        (req.user.role === 'reseller' && user.role === 'reseller'); // Resellers can see other resellers for B2B
      
      if (!canAccess) {
        return res.status(403).send("Access denied");
      }
      
      // Return user without password
      const { password, ...safeUser } = user;
      res.json(safeUser);
    } catch (error: any) {
      console.error("Service order creation error:", error);
      res.status(500).send(error.message);
    }
  });
  // GET /api/my-parent-reseller - Get parent reseller info for sub-resellers, reseller_staff, and repair_center
  app.get("/api/my-parent-reseller", requireAuth, async (req, res) => {
    try {
      if (!req.user) return res.status(401).send("Unauthorized");
      
      // For reseller_staff, use resellerId; for sub-resellers, use parentResellerId
      // For repair_center, look up from repair_centers table
      let targetResellerId = null;
      
      if ((req.user.role === 'repair_center' || req.user.role === 'repair_center_staff') && req.user.repairCenterId) {
        // Repair center user: find the repair center and get its resellerId
        if (req.user.repairCenterId) {
          const repairCenter = await storage.getRepairCenter(req.user.repairCenterId);
          if (repairCenter) {
            targetResellerId = repairCenter.resellerId;
          }
        }
        // Fallback to user's resellerId if available
        if (!targetResellerId && req.user.resellerId) {
          targetResellerId = req.user.resellerId;
        }
      } else if (req.user.role === 'reseller_staff' && req.user.resellerId) {
        targetResellerId = req.user.resellerId;
      } else if ((req.user as any).parentResellerId) {
        targetResellerId = (req.user as any).parentResellerId;
      }
      
      if (!targetResellerId) {
        return res.status(404).json({ error: "No parent reseller" });
      }
      
      const parentReseller = await storage.getUser(targetResellerId);
      if (!parentReseller || parentReseller.role !== 'reseller') {
        return res.status(404).json({ error: "Parent reseller not found" });
      }
      
      res.json({
        id: parentReseller.id,
        fullName: parentReseller.fullName,
        logoUrl: parentReseller.logoUrl,
        ragioneSociale: parentReseller.ragioneSociale,
      });
    } catch (error: any) {
      console.error("Service order creation error:", error);
      res.status(500).send(error.message);
    }
  });
