      doc.rect(50, doc.y, 500, 50).stroke();
      const boxY = doc.y + 10;
      doc.fontSize(10).font('Helvetica-Bold').text('PRATICA RECUPERO DATI', 60, boxY);
      doc.font('Helvetica').text(`Numero: ${job.jobNumber}`, 60, boxY + 15);
