  // ----- UTILITY PRACTICES -----

  // GET /api/utility/practices - List utility practices
  app.get("/api/utility/practices", requireAuth, async (req, res) => {
    try {
      if (!req.user) return res.status(401).send("Unauthorized");
      
      let filters: { customerId?: string; resellerId?: string; status?: string; supplierId?: string } = {};
      
      // RBAC: filter based on role
      if (req.user.role === 'customer') {
        filters.customerId = req.user.id;
      } else if ((req.user.role === 'repair_center' || req.user.role === 'repair_center_staff') && req.user.repairCenterId) {
        // Repair center sees only their own practices
        const repairCenterId = req.user.repairCenterId;
        if (!repairCenterId) {
          return res.json([]);
        }
        // Get all practices and filter by repairCenterId
        if (req.query.status) {
          filters.status = req.query.status as string;
        }
        if (req.query.supplierId) {
          filters.supplierId = req.query.supplierId as string;
        }
        const allPractices = await storage.listUtilityPractices(filters);
        const filtered = allPractices.filter(p => p.repairCenterId === repairCenterId);
        
        // Enrich with product count
        const enrichedPractices = await Promise.all(
          filtered.map(async (practice) => {
            if (practice.itemType === 'product' || practice.itemType === 'service_with_products') {
              const practiceProducts = await storage.listUtilityPracticeProducts(practice.id);
              return { ...practice, productCount: practiceProducts.length, practiceProducts };
            }
            return { ...practice, productCount: 0, practiceProducts: [] };
          })
        );
        return res.json(enrichedPractices);
      } else if (req.user.role === 'reseller') {
        // Reseller sees their own practices + practices from their repair centers
        const resellerRepairCenters = await storage.listRepairCenters();
        const myRepairCenterIds = resellerRepairCenters
          .filter(rc => rc.resellerId === req.user!.id)
          .map(rc => rc.id);
        
        if (req.query.status) {
          filters.status = req.query.status as string;
        }
        if (req.query.supplierId) {
          filters.supplierId = req.query.supplierId as string;
        }
        
        const allPractices = await storage.listUtilityPractices(filters);
        // Filter: resellerId matches OR repairCenterId is one of reseller's centers
        const filtered = allPractices.filter(p => 
          p.resellerId === req.user!.id || 
          (p.repairCenterId && myRepairCenterIds.includes(p.repairCenterId))
        );
        
        // Enrich with product count
        const enrichedPractices = await Promise.all(
          filtered.map(async (practice) => {
            if (practice.itemType === 'product' || practice.itemType === 'service_with_products') {
              const practiceProducts = await storage.listUtilityPracticeProducts(practice.id);
              return { ...practice, productCount: practiceProducts.length, practiceProducts };
            }
            return { ...practice, productCount: 0, practiceProducts: [] };
          })
        );
        return res.json(enrichedPractices);
      }
      // Admin sees all
      
      if (req.query.status) {
        filters.status = req.query.status as string;
      }
      if (req.query.supplierId) {
        filters.supplierId = req.query.supplierId as string;
      }
      
      const practices = await storage.listUtilityPractices(filters);
      
      // Enrich with product count for each practice (for product or service_with_products types)
      const enrichedPractices = await Promise.all(
        practices.map(async (practice) => {
          if (practice.itemType === 'product' || practice.itemType === 'service_with_products') {
            const practiceProducts = await storage.listUtilityPracticeProducts(practice.id);
            return { 
              ...practice, 
              productCount: practiceProducts.length,
              practiceProducts: practiceProducts
            };
          }
          return { ...practice, productCount: 0, practiceProducts: [] };
        })
      );
      
      res.json(enrichedPractices);
    } catch (error: any) {
      console.error("Service order creation error:", error);
      res.status(500).send(error.message);
    }
  });

  // GET /api/utility/practices/:id - Get utility practice
  app.get("/api/utility/practices/:id", requireAuth, async (req, res) => {
    try {
      if (!req.user) return res.status(401).send("Unauthorized");
      
      const practice = await storage.getUtilityPractice(req.params.id);
      if (!practice) {
        return res.status(404).send("Pratica utility non trovata");
      }
      
      // RBAC check
      if (req.user.role === 'customer' && practice.customerId !== req.user.id) {
        return res.status(403).send("Accesso negato");
      }
      if ((req.user.role === 'repair_center' || req.user.role === 'repair_center_staff') && req.user.repairCenterId) {
        // Repair center can only see their own practices
        if (practice.repairCenterId !== req.user.repairCenterId) {
          return res.status(403).send("Accesso negato");
        }
      }
      if (req.user.role === 'reseller') {
        // Reseller can see their own practices OR practices from their repair centers
        const resellerRepairCenters = await storage.listRepairCenters();
        const myRepairCenterIds = resellerRepairCenters
          .filter(rc => rc.resellerId === req.user!.id)
          .map(rc => rc.id);
        
        const isOwnPractice = practice.resellerId === req.user.id;
        const isFromMyRepairCenter = practice.repairCenterId && myRepairCenterIds.includes(practice.repairCenterId);
        
        if (!isOwnPractice && !isFromMyRepairCenter) {
          return res.status(403).send("Accesso negato");
        }
      }
      
      // Enrich with supplier, service, product info and practice products
      const [supplier, service, product, practiceProducts] = await Promise.all([
        practice.supplierId ? storage.getUtilitySupplier(practice.supplierId) : null,
        practice.serviceId ? storage.getUtilityService(practice.serviceId) : null,
        practice.productId ? storage.getProduct(practice.productId) : null,
        storage.listUtilityPracticeProducts(practice.id),
      ]);
      
      // Enrich with reseller and repair center info (minimal fields only for security)
      let reseller = null;
      let parentReseller = null;
      let repairCenter = null;
      
      if (practice.resellerId) {
        const fullReseller = await storage.getUser(practice.resellerId);
        if (fullReseller) {
          reseller = {
            id: fullReseller.id,
            fullName: fullReseller.fullName,
            username: fullReseller.username,
            parentResellerId: (fullReseller as any).parentResellerId || null,
          };
          // Se è un sotto-rivenditore, carica anche il parent (minimal fields)
          if ((fullReseller as any).parentResellerId) {
            const fullParent = await storage.getUser((fullReseller as any).parentResellerId);
            if (fullParent) {
              parentReseller = {
                id: fullParent.id,
                fullName: fullParent.fullName,
                username: fullParent.username,
              };
            }
          }
        }
      }
      
      if (practice.repairCenterId) {
        const fullRepairCenter = await storage.getRepairCenter(practice.repairCenterId);
        if (fullRepairCenter) {
          repairCenter = {
            id: fullRepairCenter.id,
            name: fullRepairCenter.name,
          };
        }
      }
      
      // Enrich practice products with product details
      const productsWithDetails = await Promise.all(
        practiceProducts.map(async (pp) => {
          const productDetail = await storage.getProduct(pp.productId);
          return { ...pp, product: productDetail };
        })
      );
      
      res.json({ ...practice, supplier, service, product, practiceProducts: productsWithDetails, reseller, parentReseller, repairCenter });
    } catch (error: any) {
      console.error("Service order creation error:", error);
      res.status(500).send(error.message);
    }
  });

  // POST /api/utility/practices - Create utility practice
  app.post("/api/utility/practices", requireAuth, requireRole("admin", "reseller", "repair_center"), async (req, res) => {
    try {
      if (!req.user) return res.status(401).send("Unauthorized");
      
      const { products: productsArray, ...practiceData } = req.body;
      
      // If admin, validate optional resellerId and repairCenterId (mutual exclusivity enforced)
      if (req.user.role === 'admin') {
        // Enforce mutual exclusivity: cannot have both resellerId and repairCenterId
        if (practiceData.resellerId && practiceData.repairCenterId) {
          return res.status(400).send("Non è possibile assegnare la pratica sia a un rivenditore che a un centro riparazione");
        }
        
        if (practiceData.resellerId) {
          const reseller = await storage.getUser(practiceData.resellerId);
          if (!reseller || (reseller.role !== 'reseller' && reseller.role !== 'sub_reseller')) {
            return res.status(400).send("Rivenditore non valido");
          }
          // Clear repairCenterId to ensure clean state
          practiceData.repairCenterId = null;
        } else if (practiceData.repairCenterId) {
          const repairCenter = await storage.getRepairCenter(practiceData.repairCenterId);
          if (!repairCenter) {
            return res.status(400).send("Centro riparazione non valido");
          }
          // Clear resellerId to ensure clean state
          practiceData.resellerId = null;
        }
        // If neither is specified, both remain null (admin-owned practice)
      }
      
      // If reseller, handle resellerId or repairCenterId (can be self, sub-reseller, or repair center)
      if (req.user.role === 'reseller') {
        if (practiceData.repairCenterId) {
          // Validate that the specified repairCenterId belongs to the current reseller
          const resellerCenters = await storage.getRepairCentersForReseller(req.user.id);
          const isValidCenter = resellerCenters.some(c => c.id === practiceData.repairCenterId);
          if (!isValidCenter) {
            return res.status(403).send("Puoi creare pratiche solo per i tuoi centri di riparazione");
          }
          // Set repairCenterId and leave resellerId null for repair center practices
          practiceData.resellerId = null;
        } else if (practiceData.resellerId && practiceData.resellerId !== req.user.id) {
          // Validate that the specified resellerId is a sub-reseller of the current user
          const childResellers = await storage.getChildResellers(req.user.id);
          const isValidSubReseller = childResellers.some(r => r.id === practiceData.resellerId);
          if (!isValidSubReseller) {
            return res.status(403).send("Puoi creare pratiche solo per te stesso o per i tuoi sub-rivenditori");
          }
          // Keep the specified resellerId for sub-reseller
        } else {
          // Default to current user
          practiceData.resellerId = req.user.id;
        }
      }
      
      const validated = insertUtilityPracticeSchema.parse(practiceData);
      
      // XOR validation: for service/service_with_products, require either serviceId OR customServiceName (not both)
      if (validated.itemType === 'service' || validated.itemType === 'service_with_products') {
        const hasService = !!validated.serviceId;
        const hasCustomService = !!validated.customServiceName?.trim();
        
        if (!hasService && !hasCustomService) {
          return res.status(400).send("Per pratiche di tipo servizio, è richiesto un servizio dal catalogo oppure un servizio temporaneo");
        }
        if (hasService && hasCustomService) {
          return res.status(400).send("Selezionare un servizio dal catalogo OPPURE inserire un servizio temporaneo, non entrambi");
        }
      } else if (validated.itemType === 'product') {
        // For product-only practices, clear service fields
        validated.serviceId = null;
        validated.customServiceName = null;
      }
      
      // If products array is provided, create practice with products transactionally
      if (productsArray && Array.isArray(productsArray) && productsArray.length > 0) {
        const validProducts = productsArray
          .filter((p: any) => p.productId)
          .map((p: any) => ({
            productId: p.productId,
            quantity: p.quantity || 1,
            unitPriceCents: p.unitPriceCents || 0,
            notes: p.notes || null,
          }));
        
        if (validProducts.length > 0) {
          const result = await storage.createUtilityPracticeWithProducts(validated, validProducts);
          return res.status(201).json(result.practice);
        }
      }
      
      // Create practice without products
      const practice = await storage.createUtilityPractice(validated);
      res.status(201).json(practice);
    } catch (error: any) {
      console.error("Service order creation error:", error);
      res.status(400).send(error.message);
    }
  });

  // PATCH /api/utility/practices/:id - Update utility practice
  app.patch("/api/utility/practices/:id", requireAuth, requireRole("admin", "reseller", "repair_center"), async (req, res) => {
    try {
      if (!req.user) return res.status(401).send("Unauthorized");
      
      const practice = await storage.getUtilityPractice(req.params.id);
      if (!practice) {
        return res.status(404).send("Pratica utility non trovata");
      }
      
      // Resellers can only update their own practices
      if (req.user.role === 'reseller' && practice.resellerId !== req.user.id) {
        return res.status(403).send("Accesso negato");
      }
      
      const { products: productsArray, ...practiceData } = req.body;
      
      // If admin, validate resellerId and repairCenterId assignments (mutual exclusivity enforced)
      if (req.user.role === 'admin') {
        const finalResellerId = practiceData.resellerId !== undefined ? practiceData.resellerId : practice.resellerId;
        const finalRepairCenterId = practiceData.repairCenterId !== undefined ? practiceData.repairCenterId : practice.repairCenterId;
        
        // Enforce mutual exclusivity: cannot have both
        if (finalResellerId && finalRepairCenterId) {
          return res.status(400).send("Non è possibile assegnare la pratica sia a un rivenditore che a un centro riparazione");
        }
        
        // Validate resellerId if being set
        if (practiceData.resellerId) {
          const reseller = await storage.getUser(practiceData.resellerId);
          if (!reseller || (reseller.role !== 'reseller' && reseller.role !== 'sub_reseller')) {
            return res.status(400).send("Rivenditore non valido");
          }
          // Clear repairCenterId if assigning to reseller
          practiceData.repairCenterId = null;
        }
        
        // Validate repairCenterId if being set
        if (practiceData.repairCenterId) {
          const repairCenter = await storage.getRepairCenter(practiceData.repairCenterId);
          if (!repairCenter) {
            return res.status(400).send("Centro riparazione non valido");
          }
          // Clear resellerId if assigning to repair center
          practiceData.resellerId = null;
        }
      }
      
      // XOR validation for service fields on update
      const finalItemType = practiceData.itemType || practice.itemType;
      if (finalItemType === 'service' || finalItemType === 'service_with_products') {
        const finalServiceId = practiceData.serviceId !== undefined ? practiceData.serviceId : practice.serviceId;
        const finalCustomService = practiceData.customServiceName !== undefined ? practiceData.customServiceName : practice.customServiceName;
        const hasService = !!finalServiceId;
        const hasCustomService = !!finalCustomService?.trim();
        
        if (!hasService && !hasCustomService) {
          return res.status(400).send("Per pratiche di tipo servizio, è richiesto un servizio dal catalogo oppure un servizio temporaneo");
        }
        if (hasService && hasCustomService) {
          return res.status(400).send("Selezionare un servizio dal catalogo OPPURE inserire un servizio temporaneo, non entrambi");
        }
      } else if (finalItemType === 'product') {
        // For product-only practices, clear service fields
        practiceData.serviceId = null;
        practiceData.customServiceName = null;
      }
      
      const updated = await storage.updateUtilityPractice(req.params.id, practiceData);
      
      // If products array is provided, sync practice products transactionally
      if (productsArray && Array.isArray(productsArray)) {
        const validProducts = productsArray
          .filter((p: any) => p.productId)
          .map((p: any) => ({
            productId: p.productId,
            quantity: p.quantity || 1,
            unitPriceCents: p.unitPriceCents || 0,
            notes: p.notes || null,
          }));
        
        if (validProducts.length > 0) {
          await storage.syncUtilityPracticeProductsTransactional(req.params.id, validProducts);
        } else {
          // If empty array, just delete all products
          await storage.deleteUtilityPracticeProductsByPractice(req.params.id);
        }
      }
      
      res.json(updated);
    } catch (error: any) {
      console.error("Service order creation error:", error);
      res.status(400).send(error.message);
    }
  });

