  // ----- UTILITY PRACTICE STATUS UPDATE -----

  // PATCH /api/utility/practices/:id/status - Update practice status with history
  app.patch("/api/utility/practices/:id/status", requireAuth, requireRole("admin", "reseller", "repair_center"), async (req, res) => {
    try {
      if (!req.user) return res.status(401).send("Unauthorized");
      
      const practice = await storage.getUtilityPractice(req.params.id);
      if (!practice) return res.status(404).send("Pratica non trovata");
      
      // RBAC check for repair_center and resellers
      if ((req.user.role === 'repair_center' || req.user.role === 'repair_center_staff') && req.user.repairCenterId) {
        if (practice.repairCenterId !== req.user.repairCenterId) {
          return res.status(403).send("Accesso negato");
        }
      }
      if (req.user.role === 'reseller') {
        const resellerRepairCenters = await storage.listRepairCenters();
        const myRepairCenterIds = resellerRepairCenters
          .filter(rc => rc.resellerId === req.user!.id)
          .map(rc => rc.id);
        const isOwnPractice = practice.resellerId === req.user.id;
        const isFromMyRepairCenter = practice.repairCenterId && myRepairCenterIds.includes(practice.repairCenterId);
        if (!isOwnPractice && !isFromMyRepairCenter) {
          return res.status(403).send("Accesso negato");
        }
      }
      
      const { status, reason, carrier, carrierName, trackingNumber } = req.body;
      
      // Create state history entry
      await storage.createUtilityPracticeStateHistory({
        practiceId: req.params.id,
        fromStatus: practice.status,
        toStatus: status,
        reason,
        changedBy: req.user.id,
      });
      
      // Create timeline event
      await storage.createUtilityPracticeTimelineEvent({
        practiceId: req.params.id,
        eventType: 'status_change',
        title: `Stato cambiato: ${practice.status} → ${status}`,
        description: reason,
        payload: { fromStatus: practice.status, toStatus: status },
        createdBy: req.user.id,
      });
      
      // Update practice with auto-populated dates based on status
      const updateData: any = { status };
      
      // Auto-populate submittedAt when status changes to "inviata"
      if (status === 'inviata' && !practice.submittedAt) {
        updateData.submittedAt = new Date();
      }
      
      // Auto-populate activatedAt when status changes to "completata"
      if (status === 'completata' && !practice.activatedAt) {
        updateData.activatedAt = new Date();
      }
      
      const updated = await storage.updateUtilityPractice(req.params.id, updateData);
      
      // Auto-create commission when practice is completed
      if (status === 'completata' && practice.status !== 'completata') {
        // Check if commission already exists for this practice
        const existingCommissions = await storage.listUtilityCommissions({ practiceId: req.params.id });
        
        if (existingCommissions.length === 0) {
          // Calculate commission amount
          let commissionAmount = practice.commissionAmountCents || 0;
          
          // If no commission on practice, try to get from service
          if (commissionAmount === 0 && practice.serviceId) {
            const service = await storage.getUtilityService(practice.serviceId);
            if (service) {
              // Use service commission (one-time activation or fixed)
              if (service.commissionOneTime) {
                commissionAmount = service.commissionOneTime;
              } else if (service.commissionFixed) {
                commissionAmount = service.commissionFixed;
              } else if (service.commissionPercent && practice.monthlyPriceCents) {
                // Calculate percentage on monthly price
                commissionAmount = Math.round(practice.monthlyPriceCents * (service.commissionPercent / 100));
              }
            }
          }
          
          // Create commission if amount > 0
          if (commissionAmount > 0) {
            const now = new Date();
            const commission = await storage.createUtilityCommission({
              practiceId: req.params.id,
              periodMonth: now.getMonth() + 1, // 1-12
              periodYear: now.getFullYear(),
              amountCents: commissionAmount,
              status: 'pending',
              accruedAt: now,
              notes: `Commissione automatica per pratica ${practice.practiceNumber}`,
            });
            
            // Create timeline event for commission
            await storage.createUtilityPracticeTimelineEvent({
              practiceId: req.params.id,
              eventType: 'commissione_maturata',
              title: `Commissione maturata: €${(commissionAmount / 100).toFixed(2)}`,
              description: `Commissione riconosciuta a ${practice.resellerId ? 'Reseller' : 'Repair Center'}`,
              payload: { commissionId: commission.id, amountCents: commissionAmount },
              createdBy: req.user.id,
            });
          }
        }
      }
      
      // Generazione fattura automatica quando pratica completata
      let invoice = null;
      if (status === 'completata' && practice.status !== 'completata' && practice.customerId) {
        const service = practice.serviceId ? await storage.getUtilityService(practice.serviceId) : null;
        let invoiceAmount = practice.monthlyPriceCents || 0;
        if (service?.activationCost) {
          invoiceAmount += service.activationCost;
        }
        if (invoiceAmount > 0) {
          const repairCenterId = practice.repairCenterId || '';
          const invoiceNumber = repairCenterId 
            ? await storage.generateInvoiceNumber(repairCenterId)
            : `UTL-${new Date().getFullYear()}-${Date.now()}`;
          invoice = await storage.createInvoice({
            invoiceNumber,
            customerId: practice.customerId,
            repairCenterId: repairCenterId || undefined,
            resellerId: practice.resellerId || undefined,
            source: 'other',
            amount: invoiceAmount,
            tax: Math.round(invoiceAmount * 22 / 122),
            total: invoiceAmount,
            paymentStatus: 'pending',
            paymentMethod: 'bank_transfer',
            notes: `Fattura per attivazione pratica utility ${practice.practiceNumber}`,
          });
          await storage.createUtilityPracticeTimelineEvent({
            practiceId: req.params.id,
            eventType: 'invoice_created',
            title: `Fattura generata: €${(invoiceAmount / 100).toFixed(2)}`,
            description: `Fattura ${invoiceNumber} creata automaticamente`,
            payload: { invoiceId: invoice.id, amountCents: invoiceAmount },
            createdBy: req.user.id,
          });
        }
      }
      
      if (practice.customerId) { try { await storage.createNotification({ userId: practice.customerId, type: "system", title: "Aggiornamento pratica", message: `La pratica #${practice.practiceNumber || practice.id} è stata aggiornata allo stato: ${status}`, data: JSON.stringify({ practiceId: practice.id }) }); } catch(e) { console.error("Notification error:", e); } }
      if (practice.resellerId && req.user.id !== practice.resellerId) { try { await storage.createNotification({ userId: practice.resellerId, type: "system", title: "Aggiornamento pratica", message: `La pratica #${practice.practiceNumber || practice.id} è stata aggiornata allo stato: ${status}`, data: JSON.stringify({ practiceId: practice.id }) }); } catch(e) { console.error("Notification error:", e); } }
      res.json({ practice: updated, invoice });
    } catch (error: any) {
      console.error("Service order creation error:", error);
      res.status(400).send(error.message);
    }
  });

  // ----- UTILITY REPORTS -----

  // GET /api/utility/reports/summary - Get utility summary report
  app.get("/api/utility/reports/summary", requireAuth, requireRole("admin", "reseller", "repair_center"), async (req, res) => {
    try {
      if (!req.user) return res.status(401).send("Unauthorized");
      
      const year = req.query.year ? parseInt(req.query.year as string) : new Date().getFullYear();
      
      // Get practices based on role
      let practicesFilters: { resellerId?: string; repairCenterId?: string } = {};
      if (req.user.role === 'reseller') {
        practicesFilters.resellerId = req.user.id;
      } else if ((req.user.role === 'repair_center' || req.user.role === 'repair_center_staff') && req.user.repairCenterId) {
        practicesFilters.repairCenterId = req.user.repairCenterId || undefined;
      }
      
      let practices = await storage.listUtilityPractices(practicesFilters);
      
      // For resellers, also include practices from their repair centers
      if (req.user.role === 'reseller') {
        const resellerRepairCenters = await storage.listRepairCenters();
        const myRepairCenterIds = resellerRepairCenters
          .filter(rc => rc.resellerId === req.user!.id)
          .map(rc => rc.id);
        const allPractices = await storage.listUtilityPractices({});
        const repairCenterPractices = allPractices.filter(
          p => p.repairCenterId && myRepairCenterIds.includes(p.repairCenterId)
        );
        practices = [...practices, ...repairCenterPractices.filter(rcp => !practices.some(p => p.id === rcp.id))];
      }
      
      const commissions = await storage.listUtilityCommissions({ periodYear: year });
      const suppliers = await storage.listUtilitySuppliers();
      
      // Filter commissions for resellers and repair_centers
      let relevantCommissions = commissions;
      if (req.user.role === 'reseller' || req.user.role === 'repair_center') {
        const practiceIds = practices.map(p => p.id);
        relevantCommissions = commissions.filter(c => practiceIds.includes(c.practiceId));
      }
      
      // Calculate stats by category
      const byCategory: Record<string, { count: number; revenue: number; commissions: number }> = {};
      const byStatus: Record<string, number> = {};
      
      for (const practice of practices) {
        const service = await storage.getUtilityService(practice.serviceId);
        const category = service?.category || 'altro';
        
        if (!byCategory[category]) {
          byCategory[category] = { count: 0, revenue: 0, commissions: 0 };
        }
        byCategory[category].count++;
        byCategory[category].revenue += practice.monthlyPriceCents || 0;
        byCategory[category].commissions += practice.commissionAmountCents || 0;
        
        byStatus[practice.status] = (byStatus[practice.status] || 0) + 1;
      }
      
      // Calculate total commissions
      const totalCommissions = relevantCommissions.reduce((sum, c) => sum + c.amountCents, 0);
      const pendingCommissions = relevantCommissions.filter(c => c.status === 'pending').reduce((sum, c) => sum + c.amountCents, 0);
      const paidCommissions = relevantCommissions.filter(c => c.status === 'paid').reduce((sum, c) => sum + c.amountCents, 0);
      
      res.json({
        year,
        totalPractices: practices.length,
        activePractices: practices.filter(p => p.status === 'completata').length,
        byCategory,
        byStatus,
        commissions: {
          total: totalCommissions,
          pending: pendingCommissions,
          paid: paidCommissions,
        },
        supplierCount: suppliers.length,
      });
    } catch (error: any) {
      console.error("Service order creation error:", error);
      res.status(500).send(error.message);
    }
  });

