  // Marketplace - dettaglio singolo prodotto con tutti i venditori
  app.get("/api/marketplace/products/:productId", async (req, res) => {
    try {
      const { productId } = req.params;
      
      const product = await storage.getProduct(productId);
      if (!product) {
        return res.status(404).json({ error: "Prodotto non trovato" });
      }
      
      // Get specs based on product type
      let specs = null;
      if (product.productType === 'dispositivo') {
        specs = await storage.getSmartphoneSpecs(product.id);
      } else if (product.productType === 'accessorio') {
        specs = await storage.getAccessorySpecs(product.id);
      }
      
      // Get all sellers for this product from marketplace
      const marketplaceProducts = await storage.getMarketplaceProducts();
      const productEntry = marketplaceProducts.find(p => p.id === productId);
      
      const sellers: Array<{ resellerId: string; resellerName: string; price: number; isPublished: boolean; isAdmin: boolean }> = [];
      
      if (productEntry && productEntry.sellers && productEntry.sellers.length > 0) {
        for (const s of productEntry.sellers) {
          sellers.push({
            resellerId: s.sellerId,
            resellerName: s.sellerName,
            price: s.price,
            isPublished: true,
            isAdmin: s.isAdmin,
          });
        }
      }
      
      // If no sellers found, use product creator as fallback
      if (sellers.length === 0) {
        if (product.createdBy) {
          sellers.push({
            resellerId: product.createdBy,
            resellerName: 'Venditore',
            price: product.unitPrice,
            isPublished: true,
            isAdmin: false,
          });
        } else {
          const allUsers = await storage.listUsers();
          const adminUser = allUsers.find((u) => u.role === 'admin');
          sellers.push({
            resellerId: adminUser?.id || 'system',
            resellerName: adminUser?.fullName || 'Admin Shop',
            price: product.unitPrice,
            isPublished: true,
            isAdmin: true,
          });
        }
      }
      
      const lowestPrice = Math.min(...sellers.map(s => s.price));
      
      // Get warehouse stock for availability
      const warehouseStock = await storage.getProductWarehouseStocks(productId);
      const totalStock = warehouseStock.reduce((sum, ws) => sum + ws.quantity, 0);
      
      res.json({
        product: {
          id: product.id,
          name: product.name,
          description: product.description,
          sku: product.sku,
          category: product.category,
          brand: product.brand,
          imageUrl: product.imageUrl,
          unitPrice: product.unitPrice,
          productType: product.productType,
        },
        specs,
        sellers,
        lowestPrice: sellers.length > 0 ? Math.min(...sellers.map(s => s.price)) : product.unitPrice,
        sellerCount: sellers.length,
        totalStock,
        hasValidSellers: sellers.length > 0,
      });
    } catch (error: any) {
      console.error("Service order creation error:", error);
      res.status(500).json({ error: error.message });
    }
  });

