  // ==========================================

  app.get("/api/shop/:resellerId/cart", async (req, res) => {
    try {
      const { resellerId } = req.params;
      const customerId = req.user?.id || null;
      const sessionId = req.session?.id || null;
      
      let cart = await storage.getActiveCart(customerId, sessionId, resellerId);
      
      if (!cart) {
        cart = await storage.createCart({
          resellerId,
          customerId,
          sessionId: customerId ? null : sessionId
        });
      }
      
      const items = await storage.listCartItems(cart.id);
      
      const itemsWithProducts = await Promise.all(items.map(async (item) => {
        const product = await storage.getProduct(item.productId);
        return { ...item, product };
      }));
      
      // Get customer VAT rate from price list based on customer type
      let customerVatRate = 22; // default
      if (customerId) {
        const billingData = await storage.getBillingDataByUserId(customerId);
        const customerType = billingData?.customerType as "private" | "company" | undefined;
        const priceList = await storage.getPriceListForCustomerType(resellerId, customerType);
        if (priceList?.defaultVatRate !== undefined) {
          customerVatRate = priceList.defaultVatRate;
        }
      }
      res.json({ cart, items: itemsWithProducts, customerVatRate });
    } catch (error: any) {
      console.error("Service order creation error:", error);
      res.status(500).json({ error: error.message });
    }
  });

  app.post("/api/shop/:resellerId/cart/items", async (req, res) => {
    try {
      const { resellerId } = req.params;
      const { productId, quantity = 1 } = req.body;
      
      const customerId = req.user?.id || null;
      const sessionId = req.session?.id || null;
      
      let cart = await storage.getActiveCart(customerId, sessionId, resellerId);
      if (!cart) {
        cart = await storage.createCart({
          resellerId,
          customerId,
          sessionId: customerId ? null : sessionId
        });
      }
      
      const product = await storage.getProduct(productId);
      if (!product) return res.status(404).json({ error: "Prodotto non trovato" });
      // Verifica se il prodotto è disponibile per questo reseller:
      // 1. Prodotto proprio del reseller (createdBy === resellerId)
      // 2. Prodotto globale assegnato e pubblicato
      // 3. Prodotto globale admin (createdBy null) - admin è il venditore
      const isOwnProduct = product.createdBy === resellerId;
      let isAssignedProduct = false;
      let isAdminProduct = false;
      
      if (!isOwnProduct) {
        // Check if admin user is selling their own global product
        if (!product.createdBy) {
          const allUsers = await storage.listUsers();
          const adminUser = allUsers.find((u: any) => u.role === 'admin');
          isAdminProduct = adminUser?.id === resellerId;
        }
        if (!isAdminProduct) {
          const assignment = await storage.getResellerProduct(productId, resellerId);
          isAssignedProduct = !!assignment && assignment.isPublished;
        }
      }
      
      if (!isOwnProduct && !isAssignedProduct && !isAdminProduct) {
        return res.status(400).json({ error: "Prodotto non disponibile" });
      }
      
      const existingItem = await storage.getCartItemByProduct(cart.id, productId);
      
      if (existingItem) {
        const updated = await storage.updateCartItem(existingItem.id, {
          quantity: existingItem.quantity + quantity
        });
        res.json(updated);
      } else {
        // Calcola il prezzo corretto: proprio o assegnato
        let effectivePrice = product.unitPrice || 0; // unitPrice è in cents
        
        // Per prodotti assegnati, usa customPriceCents se disponibile
        if (!isOwnProduct && isAssignedProduct) {
          const assignment = await storage.getResellerProduct(productId, resellerId);
          if (assignment?.customPriceCents) {
            effectivePrice = assignment.customPriceCents;
          }
        }
        
        // Applica listino prezzi customer se utente loggato è cliente del reseller
        const user = req.user;
        if (user && user.role === "customer" && user.resellerId === resellerId) {
          const priceList = await storage.getPriceListForTarget(resellerId, "customer");
          if (priceList) {
            const priceListItem = await storage.getPriceForItem(priceList.id, productId, undefined);
            if (priceListItem && priceListItem.isActive) {
              effectivePrice = priceListItem.priceCents;
            }
          }
        }
        
        const unitPriceCents = effectivePrice; // Mantieni in centesimi
        const item = await storage.addCartItem({
          cartId: cart.id,
          productId,
          quantity,
          unitPrice: unitPriceCents,
          totalPrice: unitPriceCents * quantity,
          discount: 0
        });
        res.json(item);
      }
      
      // Ricalcola e aggiorna subtotal del carrello
      const allItems = await storage.listCartItems(cart.id);
      const subtotal = allItems.reduce((sum, i) => sum + (i.totalPrice || 0), 0);
      await storage.updateCart(cart.id, { subtotal, total: subtotal });
      
    } catch (error: any) {
      console.error("Service order creation error:", error);
      res.status(500).json({ error: error.message });
    }
  });

  app.put("/api/cart/items/:itemId", async (req, res) => {
    try {
      const { quantity } = req.body;
      const item = await storage.getCartItem(req.params.itemId);
      if (!item) return res.status(404).json({ error: "Item non trovato" });
      
      if (quantity < 1) {
        await storage.removeCartItem(req.params.itemId);
        // Ricalcola subtotal dopo rimozione
        const allItems = await storage.listCartItems(item.cartId);
        const subtotal = allItems.reduce((sum, i) => sum + (i.totalPrice || 0), 0);
        await storage.updateCart(item.cartId, { subtotal, total: subtotal });
        return res.json({ success: true, removed: true });
      }
      
      const newTotalPrice = item.unitPrice * quantity;
      const updated = await storage.updateCartItem(req.params.itemId, { 
        quantity,
        totalPrice: newTotalPrice
      });
      
      // Ricalcola subtotal dopo update
      const allItems = await storage.listCartItems(item.cartId);
      const subtotal = allItems.reduce((sum, i) => sum + (i.totalPrice || 0), 0);
      await storage.updateCart(item.cartId, { subtotal, total: subtotal });
      
      res.json(updated);
    } catch (error: any) {
      console.error("Service order creation error:", error);
      res.status(500).json({ error: error.message });
    }
  });

