  // Shop: Create Stripe PaymentIntent for customer checkout
  app.post("/api/shop/:resellerId/stripe-payment-intent", requireAuth, async (req, res) => {
    try {
      if (!req.user) return res.status(401).json({ error: "Non autenticato" });
      
      const { resellerId } = req.params;
      const { shippingMethodId } = req.body;
      
      // Get reseller payment config
      const paymentConfig = await storage.getPaymentConfiguration("reseller", resellerId);
      if (!paymentConfig?.stripeEnabled || !paymentConfig?.stripeSecretKey) {
        return res.status(400).json({ error: "Stripe non configurato dal venditore" });
      }
      
      // Get customer cart
      const cart = await storage.getActiveCart(req.user.id, null, resellerId);
      if (!cart) return res.status(400).json({ error: "Carrello vuoto" });
      
      const cartItems = await storage.listCartItems(cart.id);
      if (cartItems.length === 0) return res.status(400).json({ error: "Carrello vuoto" });
      
      // Calculate total from cart
      let total = cart.subtotal || 0;
      
      // Add shipping cost
      if (shippingMethodId) {
        const shippingMethod = await storage.getShippingMethod(shippingMethodId);
        total += shippingMethod?.priceCents || 0;
      }
      
      if (total <= 0) {
        return res.status(400).json({ error: "Totale ordine non valido" });
      }
      
      // Create Stripe instance with reseller's secret key
      const stripeSecretDecrypted = decryptSecret(paymentConfig.stripeSecretKey);
      const stripe = new Stripe(stripeSecretDecrypted);
      
      // Create PaymentIntent (amount already in cents)
      const paymentIntent = await stripe.paymentIntents.create({
        amount: total,
        currency: 'eur',
        metadata: {
          customerId: req.user.id,
          resellerId: resellerId,
          type: 'shop_order'
        }
      });
      
      res.json({
        clientSecret: paymentIntent.client_secret,
        publishableKey: paymentConfig.stripePublishableKey,
      });
    } catch (error: any) {
      console.error("Service order creation error:", error);
      console.error("Shop Stripe PaymentIntent error:", error);
      res.status(500).json({ error: error.message || "Errore creazione pagamento Stripe" });
    }
  });

  app.post("/api/shop/:resellerId/checkout", requireAuth, async (req, res) => {
    try {
      if (!req.user) return res.status(401).json({ error: "Non autenticato" });
      
      const { resellerId } = req.params;
      const {
        shippingAddressId,
        billingAddressId,
        shippingMethodId,
        deliveryType = 'shipping',
        paymentMethod,
        customerNotes
      } = req.body;
      
      // Validate payment method against reseller's enabled methods
      if (paymentMethod) {
        const paymentConfig = await storage.getPaymentConfiguration("reseller", resellerId);
        const methodEnabled = {
          card: paymentConfig?.stripeEnabled,
          bank_transfer: paymentConfig?.bankTransferEnabled,
          paypal: paymentConfig?.paypalEnabled,
        };
        if (!methodEnabled[paymentMethod as keyof typeof methodEnabled]) {
          return res.status(400).json({ error: "Metodo di pagamento non disponibile" });
        }
      }
      
      const cart = await storage.getActiveCart(req.user.id, null, resellerId);
      if (!cart) return res.status(400).json({ error: "Carrello vuoto" });
      
      const cartItems = await storage.listCartItems(cart.id);
      if (cartItems.length === 0) return res.status(400).json({ error: "Carrello vuoto" });
      
      const shippingAddress = shippingAddressId ? await storage.getCustomerAddress(shippingAddressId) : null;
      const billingAddress = billingAddressId ? await storage.getCustomerAddress(billingAddressId) : shippingAddress;
      
      // Calcola costo spedizione dal metodo selezionato
      let shippingCost = 0;
      if (shippingMethodId) {
        const shippingMethod = await storage.getShippingMethod(shippingMethodId);
        if (shippingMethod) {
          shippingCost = shippingMethod.priceCents || 0;
        }
      }
      
      // Calcola IVA dal listino prezzi cliente basato sul tipo cliente (company/private)
      const customerBillingData = await storage.getBillingDataByUserId(req.user.id);
      const customerType = customerBillingData?.customerType as "private" | "company" | undefined;
      const customerPriceList = await storage.getPriceListForCustomerType(resellerId, customerType);
      const vatRate = (customerPriceList as any)?.defaultVatRate ?? 22;
      const subtotal = cart.subtotal || 0;
      const discount = cart.discount || 0;
      const taxAmount = vatRate > 0 ? Math.round((subtotal * vatRate / (100 + vatRate)) * 100) / 100 : 0;
      const total = subtotal - discount + shippingCost;
      
      const orderNumber = await storage.generateOrderNumber(resellerId);
      
      const order = await storage.createSalesOrder({
        orderNumber,
        customerId: req.user.id,
        resellerId,
        status: paymentMethod === 'card' || paymentMethod === 'paypal' ? 'approved' : 'pending',
        deliveryType: deliveryType as any,
        subtotal: subtotal,
        discountAmount: discount,
        shippingCost: shippingCost,
        taxAmount: taxAmount,
        vatRate: vatRate,
        total: total,
        shippingAddressId,
        shippingRecipient: shippingAddress?.recipientName,
        shippingAddress: shippingAddress?.address,
        shippingCity: shippingAddress?.city,
        shippingProvince: shippingAddress?.province,
        shippingPostalCode: shippingAddress?.postalCode,
        shippingCountry: shippingAddress?.country,
        shippingPhone: shippingAddress?.phone,
        billingAddressId,
        billingRecipient: billingAddress?.recipientName,
        billingAddress: billingAddress?.address,
        billingCity: billingAddress?.city,
        billingProvince: billingAddress?.province,
        billingPostalCode: billingAddress?.postalCode,
        billingCountry: billingAddress?.country,
        customerNotes,
        source: 'web'
      });
      
      for (const item of cartItems) {
        const product = await storage.getProduct(item.productId);
        await storage.createSalesOrderItem({
          orderId: order.id,
          productId: item.productId,
          productName: product?.name || 'Prodotto',
          productSku: product?.sku,
          productImage: product?.imageUrl,
          quantity: item.quantity,
          unitPrice: item.unitPrice,
          discount: item.discount,
          totalPrice: item.totalPrice
        });
      }
      
      if (paymentMethod) {
        await storage.createSalesOrderPayment({
          orderId: order.id,
          method: paymentMethod,
          status: paymentMethod === 'card' || paymentMethod === 'paypal' ? 'completed' : 'pending',
          amount: cart.total,
          currency: 'EUR'
        });
      }
      
      await storage.updateCart(cart.id, { status: 'converted' });
      
      // Notifica al reseller del nuovo ordine
      await storage.createNotification({
        userId: resellerId,
        type: "system",
        title: "Nuovo ordine e-commerce",
        message: `${req.user.fullName} ha effettuato l'ordine #${order.orderNumber}`,
        data: JSON.stringify({ salesOrderId: order.id, customerId: req.user.id })
      });
      broadcastNotification(resellerId, {
        type: "new_sales_order",
        title: "Nuovo ordine e-commerce",
        message: `${req.user.fullName} ha effettuato l'ordine #${order.orderNumber}`,
        orderId: order.id
      });
      
      res.json({ order, orderNumber: order.orderNumber });
    } catch (error: any) {
      console.error("Service order creation error:", error);
      res.status(500).json({ error: error.message });
    }
  });

