  app.put("/api/sales-orders/:id/status", requireAuth, async (req, res) => {
    try {
      if (!req.user) return res.status(401).json({ error: "Non autenticato" });
      if (!['admin', 'admin_staff', 'reseller', 'reseller_staff'].includes(req.user.role)) {
        return res.status(403).json({ error: "Accesso negato" });
      }
      
      const order = await storage.getSalesOrder(req.params.id);
      if (!order) return res.status(404).json({ error: "Ordine non trovato" });
      
      if (req.user.role === 'reseller' && order.resellerId !== req.user.id) {
        return res.status(403).json({ error: "Accesso negato" });
      }
      if (req.user.role === 'reseller_staff' && order.resellerId !== req.user.resellerId) {
        return res.status(403).json({ error: "Accesso negato" });
      }
      
      const { status, reason, carrier, carrierName, trackingNumber } = req.body;
      const updated = await storage.updateSalesOrderStatus(req.params.id, status, req.user.id, reason);
      
      // Create shipment record when status is shipped
      let shipment = null;
      if (status === 'shipped') {
        shipment = await storage.createSalesOrderShipment({
          orderId: req.params.id,
          status: 'in_transit',
          carrier: carrier || null,
          carrierName: carrier === 'other' ? carrierName : null,
          trackingNumber: trackingNumber || null,
          trackingUrl: null,
        });
      }
      
      // Auto-confirm pending bank transfer payment when order is shipped
      if (status === 'shipped') {
        const payment = await storage.getPaymentByOrderId(req.params.id, 'b2c');
        if (payment && payment.status === 'pending' && payment.method === 'bank_transfer') {
          await storage.updateSalesOrderPayment(payment.id, {
            status: 'completed',
            paidAt: new Date(),
            confirmedBy: req.user.id,
            notes: payment.notes ? payment.notes + ' | Confermato automaticamente alla spedizione' : 'Confermato automaticamente alla spedizione'
          });
        }
      }
      
      // Deduct stock from reseller warehouse when shipped
      if (status === 'shipped' && order.resellerId) {
        const resellerWarehouse = await storage.getWarehouseByOwner('reseller', order.resellerId);
        if (resellerWarehouse) {
          const orderItems = await storage.listSalesOrderItems(req.params.id);
          for (const item of orderItems) {
            if (item.productId) {
              await storage.updateWarehouseStockQuantity(resellerWarehouse.id, item.productId, -item.quantity);
            }
          }
        }
      }
      
      // Auto-create invoice for resellers when order is delivered/completed
      let invoice = null;
      if ((status === 'delivered' || status === 'completed') && order.resellerId) {
        // Check if reseller is main or has autonomous invoicing
        const reseller = await storage.getUser(order.resellerId);
        if (reseller && reseller.role === 'reseller' && (!reseller.parentResellerId || reseller.hasAutonomousInvoicing)) {
          invoice = await storage.createInvoiceForSalesOrder({
            id: order.id,
            orderNumber: order.orderNumber,
            customerId: order.customerId,
            resellerId: order.resellerId,
            total: order.total,
            taxAmount: order.taxAmount || 0,
          });
        }
      }
      
      res.json({ ...updated, generatedInvoice: invoice });
    } catch (error: any) {
      console.error("Service order creation error:", error);
      res.status(500).json({ error: error.message });
    }
  });

