  // GET /api/shipments - List all shipments for reseller
  app.get("/api/shipments", requireAuth, async (req, res) => {
    try {
      if (!req.user) return res.status(401).json({ error: "Non autenticato" });
      
      const allowedRoles = ["admin", "admin_staff", "reseller", "reseller_staff", "sub_reseller"];
      if (!allowedRoles.includes(req.user.role)) {
        return res.status(403).json({ error: "Accesso negato" });
      }
      
      const statusFilter = req.query.status as string | undefined;
      
      // Get reseller ID based on role
      let resellerId: string | null = null;
      if (["reseller", "reseller_staff", "sub_reseller"].includes(req.user.role)) {
        resellerId = req.user.role === "reseller" ? req.user.id : req.user.resellerId || null;
      }
      
      // Build query using sql tagged template
      let result;
      if (resellerId && statusFilter && statusFilter !== "all") {
        result = await db.execute(sql`
          SELECT sh.*, so.order_number, so.shipping_recipient as customer_name
          FROM sales_order_shipments sh
          INNER JOIN sales_orders so ON sh.order_id = so.id
          WHERE so.reseller_id = ${resellerId} AND sh.status = ${statusFilter}
          ORDER BY sh.created_at DESC
        `);
      } else if (resellerId) {
        result = await db.execute(sql`
          SELECT sh.*, so.order_number, so.shipping_recipient as customer_name
          FROM sales_order_shipments sh
          INNER JOIN sales_orders so ON sh.order_id = so.id
          WHERE so.reseller_id = ${resellerId}
          ORDER BY sh.created_at DESC
        `);
      } else if (statusFilter && statusFilter !== "all") {
        result = await db.execute(sql`
          SELECT sh.*, so.order_number, so.shipping_recipient as customer_name
          FROM sales_order_shipments sh
          INNER JOIN sales_orders so ON sh.order_id = so.id
          WHERE sh.status = ${statusFilter}
          ORDER BY sh.created_at DESC
        `);
      } else {
        result = await db.execute(sql`
          SELECT sh.*, so.order_number, so.shipping_recipient as customer_name
          FROM sales_order_shipments sh
          INNER JOIN sales_orders so ON sh.order_id = so.id
          ORDER BY sh.created_at DESC
        `);
      }
      
      const shipments = result.rows.map((r: any) => ({
        id: r.id,
        orderId: r.order_id,
        carrier: r.carrier,
        trackingNumber: r.tracking_number,
        trackingUrl: r.tracking_url,
        status: r.status,
        notes: r.notes,
        shippedAt: r.shipped_at,
        deliveredAt: r.delivered_at,
        estimatedDelivery: r.estimated_delivery,
        createdAt: r.created_at,
        updatedAt: r.updated_at,
        orderNumber: r.order_number,
        customerName: r.customer_name
      }));
      
      res.json(shipments);
    } catch (error: any) {
      console.error("Service order creation error:", error);
      console.error("Shipments endpoint error:", error);
      res.status(500).json({ error: error.message });
    }
  });




