  // Repair Center: Create transfer request
  app.post("/api/repair-center/transfer-requests", requireRole("repair_center", "repair_center_staff"), async (req, res) => {
    try {
      if (!req.user) return res.status(401).json({ error: "Non autenticato" });
      if (!req.user.repairCenterId) return res.status(404).json({ error: "Centro di riparazione non trovato" });
      
      // Get repair center's own warehouse
      const repairCenter = await storage.getRepairCenter(req.user.repairCenterId);
      if (!repairCenter) return res.status(404).json({ error: "Centro di riparazione non trovato" });
      
      const requesterWarehouse = await storage.getWarehouseByOwner('repair_center', repairCenter.id);
      if (!requesterWarehouse) return res.status(404).json({ error: "Magazzino richiedente non trovato" });
      
      // Get source warehouse from request body or fallback to reseller's warehouse
      const { notes, items, sourceWarehouseId } = req.body;
      
      let finalSourceWarehouseId = sourceWarehouseId;
      if (!finalSourceWarehouseId) {
        const resellerWarehouse = await storage.getWarehouseByOwner('reseller', repairCenter.resellerId);
        if (!resellerWarehouse) return res.status(404).json({ error: "Magazzino fornitore non trovato" });
        finalSourceWarehouseId = resellerWarehouse.id;
      } else {
        // Validate that the provided sourceWarehouseId belongs to the reseller
        const sourceWarehouse = await storage.getWarehouse(sourceWarehouseId);
        if (!sourceWarehouse) return res.status(404).json({ error: "Magazzino sorgente non trovato" });
        if (sourceWarehouse.ownerId !== repairCenter.resellerId || sourceWarehouse.ownerType !== 'reseller') {
          return res.status(403).json({ error: "Magazzino sorgente non valido per questo reseller" });
        }
      }
      
      const request = await storage.createTransferRequest({
        requesterType: 'repair_center',
        requesterId: req.user.id,
        requesterWarehouseId: requesterWarehouse.id,
        sourceWarehouseId: finalSourceWarehouseId,
        targetResellerId: repairCenter.resellerId,
        status: paymentMethod === 'card' || paymentMethod === 'paypal' ? 'approved' : 'pending',
        notes,
      });
      
      if (items && Array.isArray(items)) {
        for (const item of items) {
          await storage.createTransferRequestItem({
            requestId: request.id,
            productId: item.productId,
            requestedQuantity: item.quantity,
          });
        }
      }
      try { await storage.createNotification({ userId: request.targetResellerId, type: "system", title: "Nuova richiesta trasferimento", message: "È stata ricevuta una nuova richiesta di trasferimento stock", data: JSON.stringify({ transferRequestId: request.id }) }); } catch(e) { console.error("Notification error:", e); }
      res.status(201).json(request);
    } catch (error: any) {
      console.error("Service order creation error:", error);
      res.status(500).json({ error: error.message });
    }
  });

