  // Repair Center: Create B2B order (purchase from reseller)
  app.post("/api/repair-center/b2b-orders", requireRole("repair_center", "repair_center_staff"), async (req, res) => {
    try {
      if (!req.user || !req.user.repairCenterId) {
        return res.status(401).json({ error: "Non autenticato" });
      }
      
      const { items, paymentMethod, shippingMethodId, notes } = req.body;
      
      if (!items || !Array.isArray(items) || items.length === 0) {
        return res.status(400).json({ error: "L'ordine deve contenere almeno un prodotto" });
      }
      
      // Get repair center to find reseller
      const repairCenter = await storage.getRepairCenter(req.user.repairCenterId);
      if (!repairCenter || !repairCenter.resellerId) {
        return res.status(400).json({ error: "Centro riparazione non associato a un rivenditore" });
      }
      
      // Validate payment method against reseller's enabled methods
      if (paymentMethod) {
        const paymentConfig = await storage.getPaymentConfiguration("reseller", repairCenter.resellerId);
        const methodEnabled = {
          bank_transfer: paymentConfig?.bankTransferEnabled ?? true, // Default to allow if not configured
          cash: true, // Cash is always available for B2B
          credit: true, // Credit is always available for B2B
          stripe: paymentConfig?.stripeEnabled,
          paypal: paymentConfig?.paypalEnabled,
        };
        if (!methodEnabled[paymentMethod as keyof typeof methodEnabled]) {
          return res.status(400).json({ error: "Metodo di pagamento non disponibile" });
        }
      }
      
      // Get reseller warehouse stock
      const resellerWarehouse = await storage.ensureDefaultWarehouse('reseller', repairCenter.resellerId, 'Reseller');
      const stock = await storage.listWarehouseStock(resellerWarehouse.id);
      const stockMap = new Map(stock.map(s => [s.productId, s.quantity]));
      
      let totalCents = 0;
      const orderItems: Array<{ productId: string; quantity: number; unitPriceCents: number; productName: string }> = [];
      
      // Get reseller's price list for repair_center (RC buying from reseller) - BULK QUERY
      const priceList = await storage.getPriceListForTarget(repairCenter.resellerId, "repair_center");
      
      // Bulk load all price list items to avoid N+1 queries
      const priceListItemsMap = new Map<string, { priceCents: number; vatRate: number }>();
      if (priceList) {
        const allPriceListItems = await storage.listPriceListItems(priceList.id);
        for (const pli of allPriceListItems) {
          if (pli.productId && pli.isActive) {
            priceListItemsMap.set(pli.productId, { priceCents: pli.priceCents, vatRate: (pli as any).vatRate ?? (priceList as any)?.defaultVatRate ?? 22 });
          }
        }
      }
      
      for (const item of items) {
        const product = await storage.getProduct(item.productId);
        if (!product || !product.isActive) {
          return res.status(400).json({ error: `Prodotto ${item.productId} non disponibile` });
        }
        
        const availableStock = stockMap.get(item.productId) || 0;
        if (item.quantity > availableStock) {
          return res.status(400).json({ error: `Stock insufficiente per ${product.name}: disponibili ${availableStock}` });
        }
        
        // B2B price priority: price_list > product.costPrice > product.unitPrice * 0.8
        let b2bPrice: number;
        const priceListItem = priceListItemsMap.get(item.productId);
        if (priceListItem) {
          b2bPrice = priceListItem.priceCents;
        } else {
          b2bPrice = product.costPrice || Math.round((product.unitPrice || 0) * 0.8);
        }
        
        const lineTotalCents = b2bPrice * item.quantity;
        totalCents += lineTotalCents;
        
        orderItems.push({
          productId: item.productId,
          quantity: item.quantity,
          unitPriceCents: b2bPrice,
          productName: product.name,
        });
      }
      
      // Calculate shipping cost
      let shippingCostCents = 0;
      if (shippingMethodId) {
        const shippingMethod = await storage.getShippingMethod(shippingMethodId);
        if (shippingMethod) {
          shippingCostCents = shippingMethod.priceCents || 0;
        }
      }
      
      // Calculate VAT (22%) on subtotal
      const taxCents = Math.round(totalCents * 0.22);
      
      // Create order with proper tax calculation
      const order = await storage.createRepairCenterPurchaseOrder({
        repairCenterId: req.user.repairCenterId,
        resellerId: repairCenter.resellerId,
        status: paymentMethod === 'card' || paymentMethod === 'paypal' ? 'approved' : 'pending',
        subtotal: totalCents,
        tax: taxCents,
        shippingCost: shippingCostCents,
        total: totalCents + taxCents + shippingCostCents,
        paymentMethod: paymentMethod || 'bank_transfer',
        shippingMethodId: shippingMethodId || null,
        notes,
      });
      
      // Create order items
      for (const item of orderItems) {
        await storage.createRepairCenterPurchaseOrderItem({
          orderId: order.id,
          productId: item.productId,
          quantity: item.quantity,
          unitPrice: item.unitPriceCents,
          totalPrice: item.unitPriceCents * item.quantity,
          productName: item.productName,
        });
      }
      
      // For automatic payment methods (PayPal, Stripe), create payment record and auto-approve
      const automaticPaymentMethods = ['paypal', 'stripe'];
      const finalPaymentMethod = paymentMethod || 'bank_transfer';
      
      if (automaticPaymentMethods.includes(finalPaymentMethod)) {
        const resellerForPayment = await storage.getUser(req.user.id);
        
        // Create payment record
        await storage.createSalesOrderPayment({
          orderId: order.id,
          orderType: 'b2b',
          orderNumber: order.orderNumber,
          method: finalPaymentMethod as any,
          status: 'completed',
          amount: order.total,
          currency: 'EUR',
          paidAt: new Date(),
          gatewayReference: notes?.match(/\[PayPal Order ID: ([^\]]+)\]/)?.[1] || null,
          notes: `Pagamento automatico ${finalPaymentMethod.toUpperCase()} per ordine B2B ${order.orderNumber}`,
          resellerId: order.resellerId,
          resellerName: resellerForPayment?.fullName || resellerForPayment?.ragioneSociale || 'N/A',
        });
        
        // Auto-approve the order
        await storage.updateRepairCenterPurchaseOrder(order.id, {
          status: 'approved',
          paymentConfirmedAt: new Date(),
        });
        
        // Update order object for response
        order.status = 'approved';
        (order as any).paymentConfirmedAt = new Date();
        
        // Auto-create invoice for automatic payments (PayPal/Stripe)
        const reseller = await storage.getUser(order.resellerId);
        if (!reseller?.parentResellerId || reseller?.hasAutonomousInvoicing) {
          await storage.createInvoiceForRepairCenterB2BOrder({
            id: order.id,
            orderNumber: order.orderNumber,
            repairCenterId: order.repairCenterId,
            resellerId: order.resellerId,
            total: order.total,
            paymentMethod: finalPaymentMethod,
          });
        }
      }

      
      const createdItems = await storage.listRepairCenterPurchaseOrderItems(order.id);
      res.status(201).json({ ...order, items: createdItems });
    } catch (error: any) {
      console.error("Service order creation error:", error);
      res.status(500).json({ error: error.message });
    }
  });

  // Repair Center: Create Stripe PaymentIntent for B2B order
  app.post("/api/repair-center/b2b-orders/stripe-payment-intent", requireRole("repair_center", "repair_center_staff"), async (req, res) => {
    try {
      if (!req.user) return res.status(401).json({ error: "Non autenticato" });
      if (!req.user.repairCenterId) return res.status(400).json({ error: "Repair Center non associato" });
      
      const { items, shippingMethodId } = req.body;
      
      if (!items || !Array.isArray(items) || items.length === 0) {
        return res.status(400).json({ error: "Nessun prodotto nell'ordine" });
      }
      
      // Get repair center and its parent reseller
      const repairCenter = await storage.getRepairCenter(req.user.repairCenterId);
      if (!repairCenter || !repairCenter.resellerId) {
        return res.status(400).json({ error: "Repair Center non associato a un rivenditore" });
      }
      
      // Get parent reseller's payment config (RC buys from their parent reseller)
      const parentConfig = await storage.getPaymentConfiguration("reseller", repairCenter.resellerId);
      if (!parentConfig?.stripeEnabled || !parentConfig?.stripeSecretKey) {
        return res.status(400).json({ error: "Stripe non configurato dal rivenditore" });
      }
      
      // Get catalog to verify products and get correct B2B prices
      const catalog = await storage.getResellerCatalogForRepairCenter(req.user.repairCenterId);
      const catalogMap = new Map(catalog.map(c => [c.product.id, c]));
      
      // Calculate total with correct B2B prices and VAT per item
      let total = 0;
      for (const item of items) {
        const catalogItem = catalogMap.get(item.productId);
        if (catalogItem) {
          const itemSubtotal = catalogItem.b2bPrice * item.quantity;
          const itemVat = Math.round(itemSubtotal * ((catalogItem.vatRate || 22) / 100));
          total += itemSubtotal + itemVat;
        }
      }
      
      // Add shipping cost
      if (shippingMethodId) {
        const shippingMethod = await storage.getShippingMethod(shippingMethodId);
        total += shippingMethod?.priceCents || 0;
      }
      
      if (total <= 0) {
        return res.status(400).json({ error: "Totale ordine non valido" });
      }
      
      // Create Stripe instance with parent reseller's secret key
      const stripeSecretDecrypted = decryptSecret(parentConfig.stripeSecretKey);
      const stripe = new Stripe(stripeSecretDecrypted);
      
      // Create PaymentIntent (amount in cents)
      const paymentIntent = await stripe.paymentIntents.create({
        amount: total,
        currency: 'eur',
        metadata: {
          repairCenterId: req.user.repairCenterId,
          resellerId: repairCenter.resellerId,
          type: 'rc_b2b_order'
        }
      });
      
      res.json({
        clientSecret: paymentIntent.client_secret,
        publishableKey: parentConfig.stripePublishableKey,
      });
    } catch (error: any) {
      console.error("Service order creation error:", error);
      console.error("RC Stripe PaymentIntent error:", error);
      res.status(500).json({ error: error.message || "Errore creazione pagamento Stripe" });
    }
  });

