  // Sync work profile from repair center opening hours
  app.post("/api/reseller/hr/work-profiles/sync-from-entity", requireRole("reseller", "reseller_staff"), async (req, res) => {
    try {
      if (!req.user) return res.status(401).json({ error: "Non autenticato" });
      const resellerId = req.user.role === 'reseller' ? req.user.id : req.user.resellerId;
      if (!resellerId) return res.status(400).json({ error: "Reseller ID non trovato" });
      
      const { entityType, entityId, profileName } = req.body;
      if (!entityType || !entityId) {
        return res.status(400).json({ error: "entityType e entityId sono richiesti" });
      }
      
      if (entityType !== 'repair_center') {
        return res.status(400).json({ error: "Solo 'repair_center' è supportato come entityType" });
      }
      
      // Get repair center with opening hours
      const repairCenter = await storage.getRepairCenter(entityId);
      if (!repairCenter) {
        return res.status(404).json({ error: "Centro riparazione non trovato" });
      }
      
      if (!repairCenter.openingHours) {
        return res.status(400).json({ error: "Il centro riparazione non ha orari configurati" });
      }
      
      // Convert opening hours to work profile format
      const openingHours = repairCenter.openingHours as Record<string, { isOpen: boolean; start?: string; end?: string; breakStart?: string | null; breakEnd?: string | null }>;
      const dayMapping: Record<string, number> = {
        'sunday': 0, 'monday': 1, 'tuesday': 2, 'wednesday': 3,
        'thursday': 4, 'friday': 5, 'saturday': 6
      };
      
      const workDays: number[] = [];
      let startTime = "09:00";
      let endTime = "18:00";
      let breakMinutes = 60;
      
      Object.entries(openingHours).forEach(([day, config]) => {
        if (config.isOpen) {
          workDays.push(dayMapping[day.toLowerCase()]);
          if (config.start) startTime = config.start;
          if (config.end) endTime = config.end;
          // Calculate break from breakStart/breakEnd if available
          if (config.breakStart && config.breakEnd) {
            const [bsH, bsM] = config.breakStart.split(':').map(Number);
            const [beH, beM] = config.breakEnd.split(':').map(Number);
            breakMinutes = (beH * 60 + beM) - (bsH * 60 + bsM);
          }
        }
      });
      
      // Sort workDays
      workDays.sort((a, b) => a - b);
      
      // Calculate daily and weekly hours
      const [startH, startM] = startTime.split(':').map(Number);
      const [endH, endM] = endTime.split(':').map(Number);
      const totalMinutes = (endH * 60 + endM) - (startH * 60 + startM) - breakMinutes;
      const dailyHours = Math.round(totalMinutes / 60 * 10) / 10;
      const weeklyHours = dailyHours * workDays.length;
      
      // Create or update work profile
      const profileData = {
        resellerId,
        name: profileName || `Orario ${repairCenter.name}`,
        description: `Profilo sincronizzato da ${repairCenter.name}`,
        weeklyHours,
        dailyHours,
        workDays,
        startTime,
        endTime,
        breakMinutes,
        sourceType: 'repair_center',
        sourceEntityId: entityId,
        isSynced: true,
        lastSyncedAt: new Date(),
        isActive: true
      };
      
      // Check if profile already exists for this entity
      const existingProfiles = await storage.listHrWorkProfiles(resellerId);
      const existingProfile = existingProfiles.find(p => 
        p.sourceType === 'repair_center' && p.sourceEntityId === entityId
      );
      
      let profile;
      if (existingProfile) {
        profile = await storage.updateHrWorkProfile(existingProfile.id, profileData);
      } else {
        profile = await storage.createHrWorkProfile(profileData);
      }
      
      // Audit log
      await storage.createHrAuditLog({
        resellerId,
        userId: req.body.userId || req.user.id,
        action: existingProfile ? 'update' : 'create',
        entityType: 'work_profile',
        entityId: profile.id,
        newValues: { synced_from: entityId, entity_type: entityType }
      });
      
      res.json(profile);
    } catch (error: any) {
      console.error("Service order creation error:", error);
      res.status(500).json({ error: error.message });
    }
  });


  // HR Work Profiles - Sync all repair centers in hierarchy
  app.post("/api/reseller/hr/work-profiles/sync-all", requireRole("reseller", "reseller_staff"), async (req, res) => {
    try {
      if (!req.user) return res.status(401).json({ error: "Non autenticato" });
      const resellerId = req.user.role === 'reseller' ? req.user.id : req.user.resellerId;
      if (!resellerId) return res.status(400).json({ error: "Reseller ID non trovato" });
      
      // Get all repair centers in hierarchy (recursive sub-resellers)
      const allSubResellerIds: string[] = [];
      const collectSubResellers = async (parentIds: string[]) => {
        if (parentIds.length === 0) return;
        const children = await storage.getUsersByParentResellerIds(parentIds);
        const newIds: string[] = [];
        for (const child of children) {
          if (!allSubResellerIds.includes(child.id)) {
            allSubResellerIds.push(child.id);
            newIds.push(child.id);
          }
        }
        if (newIds.length > 0) await collectSubResellers(newIds);
      };
      await collectSubResellers([resellerId]);
      
      const allResellerIds = [resellerId, ...allSubResellerIds];
      const repairCenters = await storage.getRepairCentersByResellerIds(allResellerIds);
      
      let synced = 0;
      let skipped = 0;
      
      for (const center of repairCenters) {
        if (!center.openingHours) { skipped++; continue; }
        
        const openingHours = center.openingHours as Record<string, { isOpen: boolean; start?: string; end?: string; breakStart?: string | null; breakEnd?: string | null }>;
        const dayMapping: Record<string, number> = { 'sunday': 0, 'monday': 1, 'tuesday': 2, 'wednesday': 3, 'thursday': 4, 'friday': 5, 'saturday': 6 };
        
        const workDays: number[] = [];
        let totalMinutes = 0, startTime = '', endTime = '', breakMinutes = 0;
        
        for (const [day, hours] of Object.entries(openingHours)) {
          if (hours.isOpen && dayMapping[day] !== undefined) {
            workDays.push(dayMapping[day]);
            if (hours.start && hours.end) {
              startTime = startTime || hours.start;
              endTime = endTime || hours.end;
              const [sh, sm] = hours.start.split(':').map(Number);
              const [eh, em] = hours.end.split(':').map(Number);
              const dayMinutes = (eh * 60 + em) - (sh * 60 + sm);
              if (hours.breakStart && hours.breakEnd) {
                const [bsh, bsm] = hours.breakStart.split(':').map(Number);
                const [beh, bem] = hours.breakEnd.split(':').map(Number);
                breakMinutes = Math.max(breakMinutes, (beh * 60 + bem) - (bsh * 60 + bsm));
              }
              totalMinutes += dayMinutes;
            }
          }
        }
        
        if (workDays.length === 0) { skipped++; continue; }
        workDays.sort((a, b) => a - b);
        const weeklyHours = Math.round((totalMinutes - (breakMinutes * workDays.length)) / 60);
        const dailyHours = Math.round(weeklyHours / workDays.length);
        
        const profileResellerId = center.subResellerId || center.resellerId || resellerId;
        const profileData = {
          resellerId: profileResellerId,
          name: `Orario ${center.name}`,
          weeklyHours, dailyHours, workDays, startTime, endTime, breakMinutes,
          sourceType: 'repair_center' as const,
          sourceEntityId: center.id,
          isSynced: true,
          lastSyncedAt: new Date(),
          isActive: true
        };
        
        const existingProfiles = await storage.listHrWorkProfiles(profileResellerId);
        const existingProfile = existingProfiles.find(p => p.sourceType === 'repair_center' && p.sourceEntityId === center.id);
        
        if (existingProfile && !existingProfile.autoSyncDisabled) {
          await storage.updateHrWorkProfile(existingProfile.id, profileData);
          synced++;
        } else if (!existingProfile) {
          await storage.createHrWorkProfile(profileData);
          synced++;
        } else {
          skipped++;
        }
      }
      
      res.json({ synced, skipped, total: repairCenters.length });
    } catch (error: any) {
      console.error("Service order creation error:", error);
      res.status(500).json({ error: error.message });
    }
  });
