  // Export sessioni POS (CSV, XLSX, PDF)
  app.get("/api/repair-center/pos/sessions/export", requireRole("repair_center", "repair_center_staff"), async (req, res) => {
    try {
      const repairCenterId = req.user!.repairCenterId || req.user!.id;
      const { format, registerId, startDate, endDate, status, period } = req.query;
      
      // Fetch sessions
      const allSessions = await storage.getPosSessionsByRepairCenter(repairCenterId, { limit: 1000, registerId: registerId as string | undefined });
      
      // Apply period filter
      const now = new Date();
      const startOfToday = new Date(now.getFullYear(), now.getMonth(), now.getDate());
      // Calculate start of week (Monday = 1) correctly handling Sunday
      const startOfWeekDate = new Date(startOfToday);
      const dayOfWeek = startOfWeekDate.getDay();
      const diff = dayOfWeek === 0 ? 6 : dayOfWeek - 1; // Sunday = 0, so go back 6 days
      startOfWeekDate.setDate(startOfWeekDate.getDate() - diff);
      const startOfMonthDate = new Date(now.getFullYear(), now.getMonth(), 1);
      
      // Apply filters including period
      let sessions = allSessions.filter(session => {
        const sessionDate = new Date(session.openedAt);
        
        // Period filter
        if (period === 'today' && sessionDate < startOfToday) return false;
        if (period === 'week' && sessionDate < startOfWeekDate) return false;
        if (period === 'month' && sessionDate < startOfMonthDate) return false;
        
        // Date range filters
        if (startDate && sessionDate < new Date(startDate as string)) return false;
        if (endDate && sessionDate > new Date(endDate as string)) return false;
        if (status && session.status !== status) return false;
        return true;
      });
      
      // Get register names
      const registers = await storage.getPosRegistersByRepairCenter(repairCenterId);
      const registerMap = new Map(registers.map(r => [r.id, r.name]));
      
      // Get operator names (only for operators in sessions - scoped to prevent data leaks)
      const operatorIds = [...new Set(sessions.map(s => s.operatorId).filter(Boolean))];
      const userMap = new Map<string, string>();
      for (const opId of operatorIds) {
        const user = await storage.getUser(opId);
        if (user) userMap.set(opId, user.fullName);
      }
      
      const formatCurrency = (cents: number) => `€ ${(cents / 100).toFixed(2)}`;
      const formatDate = (date: Date) => new Date(date).toLocaleString('it-IT');
      
      // Prepare export data
      const exportData = sessions.map(s => ({
        'ID': s.id.substring(0, 8),
        'Cassa': s.registerId ? registerMap.get(s.registerId) || 'N/D' : 'Cassa Principale',
        'Operatore': s.operatorId ? userMap.get(s.operatorId) || 'N/D' : 'N/D',
        'Stato': s.status === 'open' ? 'Aperta' : 'Chiusa',
        'Data Apertura': formatDate(s.openedAt),
        'Data Chiusura': s.closedAt ? formatDate(s.closedAt) : '-',
        'Fondo Cassa Iniziale': formatCurrency(s.openingCash),
        'Fondo Cassa Finale': s.closingCash !== null ? formatCurrency(s.closingCash) : '-',
        'Totale Vendite': formatCurrency(s.totalSales),
        'Vendite Contanti': formatCurrency(s.totalCashSales),
        'Vendite Carta': formatCurrency(s.totalCardSales),
        'Transazioni': s.totalTransactions || 0,
        'Rimborsi': formatCurrency(s.totalRefunds),
        'Differenza Cassa': s.cashDifference !== null ? formatCurrency(s.cashDifference) : '-',
        'Note Apertura': s.openingNotes || '-',
        'Note Chiusura': s.closingNotes || '-',
      }));
      
      // Define stable headers for export
      const stableHeaders = ['ID', 'Cassa', 'Operatore', 'Stato', 'Data Apertura', 'Data Chiusura', 'Fondo Cassa Iniziale', 'Fondo Cassa Finale', 'Totale Vendite', 'Vendite Contanti', 'Vendite Carta', 'Transazioni', 'Rimborsi', 'Differenza Cassa', 'Note Apertura', 'Note Chiusura'];
      
      if (format === 'csv') {
        // Generate CSV with stable headers
        const csvRows = [
          stableHeaders.join(';'),
          ...exportData.map(row => stableHeaders.map(h => `"${String((row as any)[h] ?? '').replace(/"/g, '""')}"`).join(';'))
        ];
        const csv = csvRows.join('\n');
        
        res.setHeader('Content-Type', 'text/csv; charset=utf-8');
        res.setHeader('Content-Disposition', `attachment; filename="sessioni_cassa_${new Date().toISOString().split('T')[0]}.csv"`);
        res.send('\ufeff' + csv); // BOM for Excel UTF-8
        
      } else if (format === 'xlsx') {
        // Generate XLSX
        const workbook = new ExcelJSModule.default.Workbook();
        workbook.creator = 'MonkeyPlan POS';
        workbook.created = new Date();
        
        const worksheet = workbook.addWorksheet('Sessioni Cassa');
        
        // Always add headers even if empty
        worksheet.addRow(stableHeaders);
        
        if (exportData.length > 0) {
          
          // Style header
          worksheet.getRow(1).font = { bold: true };
          worksheet.getRow(1).fill = {
            type: 'pattern',
            pattern: 'solid',
            fgColor: { argb: 'FF4A90A4' }
          };
          worksheet.getRow(1).font = { bold: true, color: { argb: 'FFFFFFFF' } };
          
        // Add data rows using stable headers
        exportData.forEach(row => {
          worksheet.addRow(stableHeaders.map(h => (row as any)[h] ?? ''));
        });
          
          // Auto-width columns
          worksheet.columns.forEach(column => {
            let maxLength = 10;
            column.eachCell?.({ includeEmpty: true }, cell => {
              const cellLength = cell.value ? String(cell.value).length : 10;
              if (cellLength > maxLength) maxLength = Math.min(cellLength, 50);
            });
            column.width = maxLength + 2;
          });
        }
        
        res.setHeader('Content-Type', 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');
        res.setHeader('Content-Disposition', `attachment; filename="sessioni_cassa_${new Date().toISOString().split('T')[0]}.xlsx"`);
        
        const buffer = await workbook.xlsx.writeBuffer();
        res.send(buffer);
        
      } else if (format === 'pdf') {
        // Generate PDF
        const PDFDocument = (await import('pdfkit')).default;
        const doc = new PDFDocument({ margin: 30, size: 'A4', layout: 'landscape' });
        
        res.setHeader('Content-Type', 'application/pdf');
        res.setHeader('Content-Disposition', `attachment; filename="sessioni_cassa_${new Date().toISOString().split('T')[0]}.pdf"`);
        
        doc.pipe(res);
        
        // Title
        doc.fontSize(18).fillColor('#1a5f7a').text('Storico Sessioni Cassa', { align: 'center' });
        doc.moveDown(0.5);
        doc.fontSize(10).fillColor('#666').text(`Generato il: ${new Date().toLocaleString('it-IT')}`, { align: 'center' });
        doc.moveDown();
        
        // Summary
        const openCount = sessions.filter(s => s.status === 'open').length;
        const closedCount = sessions.filter(s => s.status === 'closed').length;
        const totalRevenue = sessions.reduce((sum, s) => sum + (s.totalSales || 0), 0);
        const totalTx = sessions.reduce((sum, s) => sum + (s.totalTransactions || 0), 0);
        
        doc.fontSize(11).fillColor('#333');
        doc.text(`Totale Sessioni: ${sessions.length} (${openCount} aperte, ${closedCount} chiuse)`);
        doc.text(`Totale Incassi: ${formatCurrency(totalRevenue)}`);
        doc.text(`Totale Transazioni: ${totalTx}`);
        doc.moveDown();
        
        // Table headers
        const tableTop = doc.y;
        const colWidths = [60, 80, 90, 50, 80, 80, 60, 60];
        const headers = ['Cassa', 'Operatore', 'Apertura', 'Stato', 'Vendite', 'Contanti', 'Carta', 'Trans.'];
        
        doc.fontSize(9).fillColor('#fff');
        let xPos = 30;
        doc.rect(30, tableTop - 3, 760, 18).fill('#1a5f7a');
        headers.forEach((header, i) => {
          doc.fillColor('#fff').text(header, xPos + 2, tableTop, { width: colWidths[i], align: 'left' });
          xPos += colWidths[i];
        });
        
        // Table rows
        let yPos = tableTop + 20;
        doc.fillColor('#333');
        
        sessions.slice(0, 30).forEach((session, idx) => {
          if (yPos > 550) {
            doc.addPage();
            yPos = 50;
          }
          
          const bgColor = idx % 2 === 0 ? '#f8f9fa' : '#ffffff';
          doc.rect(30, yPos - 3, 760, 16).fill(bgColor);
          
          xPos = 30;
          const rowData = [
            session.registerId ? (registerMap.get(session.registerId) || 'N/D').substring(0, 12) : 'Principale',
            (session.operatorId ? userMap.get(session.operatorId) || 'N/D' : 'N/D').substring(0, 15),
            new Date(session.openedAt).toLocaleDateString('it-IT'),
            session.status === 'open' ? 'Aperta' : 'Chiusa',
            formatCurrency(session.totalSales),
            formatCurrency(session.totalCashSales),
            formatCurrency(session.totalCardSales),
            String(session.totalTransactions || 0),
          ];
          
          doc.fontSize(8).fillColor('#333');
          rowData.forEach((cell, i) => {
            doc.text(cell, xPos + 2, yPos, { width: colWidths[i], align: 'left' });
            xPos += colWidths[i];
          });
          
          yPos += 16;
        });
        
        if (sessions.length > 30) {
          doc.moveDown();
          doc.fontSize(9).fillColor('#666').text(`... e altre ${sessions.length - 30} sessioni`, { align: 'center' });
        }
        
        doc.end();
        
      } else {
        res.status(400).json({ error: "Formato non supportato. Usa: csv, xlsx, pdf" });
      }
      
    } catch (error: any) {
      console.error("Service order creation error:", error);
      console.error("Export sessions error:", error);
      res.status(500).json({ error: error.message });
    }
  });

  // Crea transazione POS
  app.post("/api/repair-center/pos/transaction", requireRole("repair_center", "repair_center_staff"), async (req, res) => {
    try {
      const repairCenterId = req.user!.repairCenterId || req.user!.id;
      const operatorId = req.user!.id;
      const { registerId } = req.body;
      
      const session = await storage.getOpenPosSession(repairCenterId, registerId);
      if (!session) return res.status(400).json({ error: "Nessuna sessione cassa aperta per questa cassa." });

      const { items, paymentMethod, customerId, discountAmount, discountPercent, cashReceived, notes, customerNotes, invoiceRequested, lotteryCode, documentType } = req.body;
      
      if (!items || items.length === 0) return res.status(400).json({ error: "Nessun articolo" });
      if (!paymentMethod) return res.status(400).json({ error: "Metodo pagamento richiesto" });
      
      // Validazione codice lotteria (8 caratteri alfanumerici)
      if (lotteryCode && (typeof lotteryCode !== "string" || !/^[A-Za-z0-9]{8}$/.test(lotteryCode))) {
        return res.status(400).json({ error: "Codice lotteria non valido (8 caratteri alfanumerici)" });
      }

      // Trova automaticamente il magazzino del repair center
      const warehouseList = await storage.listWarehouses({ 
        ownerType: 'repair_center', 
        ownerId: repairCenterId 
      });
      const repairCenterWarehouseId = warehouseList.length > 0 ? warehouseList[0].id : null;

      let subtotal = 0;
      const processedItems = [];
      
      for (const item of items) {
        // Gestisce prodotti temporanei (non registrati nel catalogo)
        if (item.isTemporary) {
          if (!item.productName || typeof item.unitPrice !== 'number') {
            return res.status(400).json({ error: "Prodotto temporaneo richiede nome e prezzo" });
          }
          const itemDiscount = item.discount || 0;
          const totalPrice = (item.unitPrice * item.quantity) - itemDiscount;
          const itemVatRate = typeof item.vatRate === 'number' ? item.vatRate : 22;
          
          processedItems.push({
            productId: null,
            productName: item.productName,
            productSku: null,
            productBarcode: null,
            isTemporary: true,
            quantity: item.quantity,
            unitPrice: item.unitPrice,
            discount: itemDiscount,
            totalPrice,
            vatRate: itemVatRate,
            warehouseId: null,
          });
          
          subtotal += totalPrice;
          continue;
        }
        
        
        // Gestisce servizi dal catalogo interventi
        if (item.isService) {
          if (!item.serviceItemId) {
            return res.status(400).json({ error: "Servizio richiede serviceItemId" });
          }
          const serviceItem = await storage.getServiceItem(item.serviceItemId);
          if (!serviceItem) return res.status(400).json({ error: `Servizio ${item.serviceItemId} non trovato` });
          
          const unitPrice = item.unitPrice ?? serviceItem.defaultPriceCents;
          const itemDiscount = item.discount || 0;
          const totalPrice = (unitPrice * item.quantity) - itemDiscount;
          const itemVatRate = typeof item.vatRate === 'number' ? item.vatRate : ((serviceItem as any).vatRate ?? 22);
          
          processedItems.push({
            productId: null,
            productName: serviceItem.name,
            productSku: serviceItem.code,
            productBarcode: null,
            serviceItemId: item.serviceItemId,
            isService: true,
            isTemporary: false,
            quantity: item.quantity,
            unitPrice: unitPrice,
            discount: itemDiscount,
            totalPrice,
            vatRate: itemVatRate,
            warehouseId: null,
          });
          
          subtotal += totalPrice;
          continue;
        }

        if (item.isWarranty) {
          if (!item.warrantyProductId) {
            return res.status(400).json({ error: "Garanzia richiede warrantyProductId" });
          }
          const warrantyProduct = await storage.getWarrantyProduct(item.warrantyProductId);
          if (!warrantyProduct) return res.status(400).json({ error: `Prodotto garanzia ${item.warrantyProductId} non trovato` });
          
          const unitPrice = item.unitPrice ?? warrantyProduct.priceInCents;
          const itemDiscount = item.discount || 0;
          const totalPrice = (unitPrice * item.quantity) - itemDiscount;
          
          processedItems.push({
            productId: null,
            productName: warrantyProduct.name,
            productSku: null,
            productBarcode: null,
            warrantyProductId: item.warrantyProductId,
            isWarranty: true,
            isService: false,
            isTemporary: false,
            quantity: item.quantity,
            unitPrice: unitPrice,
            discount: itemDiscount,
            totalPrice,
            vatRate: typeof item.vatRate === 'number' ? item.vatRate : 22,
            warehouseId: null,
          });
          
          subtotal += totalPrice;
          continue;
        }

        // Prodotto standard dal catalogo
        const product = await storage.getProduct(item.productId);
        if (!product) return res.status(400).json({ error: `Prodotto ${item.productId} non trovato` });
        
        const unitPrice = item.unitPrice || (product.unitPrice || 0);
        const itemDiscount = item.discount || 0;
        const totalPrice = (unitPrice * item.quantity) - itemDiscount;
        const itemVatRate = typeof item.vatRate === 'number' ? item.vatRate : ((product as any).vatRate ?? 22);
        
        processedItems.push({
          productId: item.productId,
          productName: product.name,
          productSku: product.sku || null,
          productBarcode: product.barcode || null,
          isTemporary: false,
          quantity: item.quantity,
          unitPrice: unitPrice,
          discount: itemDiscount,
          totalPrice,
          vatRate: itemVatRate,
          warehouseId: repairCenterWarehouseId,
        });
        
        subtotal += totalPrice;
      }

      const discount = discountAmount || (discountPercent ? Math.round(subtotal * discountPercent / 100) : 0);
      const taxableAmount = subtotal - discount;
      // Calcolo IVA multi-aliquota: prezzi netti + IVA in avanti
      let taxAmount = 0;
      let weightedTaxRate = 0;
      if (processedItems.length > 0 && taxableAmount > 0) {
        const discountRatio = subtotal > 0 ? taxableAmount / subtotal : 1;
        for (const pi of processedItems) {
          const adjustedItemTotal = Math.round(pi.totalPrice * discountRatio);
          const itemVat = pi.vatRate ?? 22;
          taxAmount += Math.round(adjustedItemTotal * itemVat / 100);
        }
        weightedTaxRate = taxableAmount > 0 ? Math.round(taxAmount / taxableAmount * 100 * 100) / 100 : 22;
      }
      const taxRate = weightedTaxRate || 22;
      const total = taxableAmount + taxAmount;

      const transactionNumber = await storage.generatePosTransactionNumber(repairCenterId);
      const dailyNumber = await storage.generatePosDailyNumber(repairCenterId, session.registerId || null);
      let changeGiven = null;
      if (paymentMethod === "cash" && cashReceived) changeGiven = cashReceived - total;

      const transaction = await storage.createPosTransaction({
        transactionNumber,
        repairCenterId,
        sessionId: session.id,
        registerId: session.registerId || null,
        customerId: customerId || null,
        operatorId,
        subtotal,
        discountAmount: discount,
        discountPercent: discountPercent || null,
        taxRate,
        taxAmount,
        total,
        paymentMethod,
        cashReceived: cashReceived || null,
        changeGiven,
        lotteryCode: lotteryCode || null,
        documentType: documentType || (invoiceRequested ? 'invoice' : 'receipt'),
        dailyNumber,
        notes: notes || null,
        customerNotes: customerNotes || null,
        invoiceRequested: invoiceRequested || false,
        status: (paymentMethod === "stripe_link" || paymentMethod === "paypal") ? "pending" : "completed",
      });

      const transactionItems = await storage.createPosTransactionItems(
        processedItems.map(item => ({ transactionId: transaction.id, ...item, inventoryDeducted: false }))
      );
      // Deduce inventario dal magazzino per ogni item con warehouseId e productId (non temporanei)
      for (const item of transactionItems) {
        if (item.warehouseId && item.productId && item.quantity > 0 && !item.isTemporary) {
          await storage.updateWarehouseStockQuantity(item.warehouseId, item.productId, -item.quantity);
          await storage.markPosItemInventoryDeducted(item.id);
        }
      }

      // Auto-create warranty records for warranty items sold to registered customers (repair-center)
      if (customerId) {
        const center = await storage.getRepairCenter(repairCenterId);
        for (const item of transactionItems) {
          if (item.isWarranty && item.warrantyProductId) {
            try {
              const wp = await storage.getWarrantyProduct(item.warrantyProductId);
              if (wp) {
                const startsAt = new Date();
                const endsAt = new Date();
                endsAt.setMonth(endsAt.getMonth() + wp.durationMonths);
                await storage.createRepairWarranty({
                  repairOrderId: null,
                  customerId,
                  warrantyProductId: wp.id,
                  sellerType: 'repair_center',
                  sellerId: repairCenterId,
                  status: 'accepted',
                  priceSnapshot: item.unitPrice,
                  durationMonthsSnapshot: wp.durationMonths,
                  coverageTypeSnapshot: wp.coverageType,
                  productNameSnapshot: wp.name,
                  startsAt,
                  endsAt,
                });
              }
            } catch (e) {
              console.error('Auto warranty creation error (RC):', e);
            }
          }
        }
      }

      const sessionTxs = await storage.getPosTransactionsBySession(session.id);
      const completedTxs = sessionTxs.filter(t => t.status === "completed");
      await storage.updatePosSessionTotals(session.id, {
        totalSales: completedTxs.reduce((sum, t) => sum + t.total, 0),
        totalTransactions: completedTxs.length,
        totalCashSales: completedTxs.filter(t => t.paymentMethod === "cash").reduce((sum, t) => sum + t.total, 0),
        totalCardSales: completedTxs.filter(t => t.paymentMethod !== "cash").reduce((sum, t) => sum + t.total, 0),
      });

      // Generazione fattura automatica se richiesta
      let invoice = null;
      if (invoiceRequested && customerId) {
        const invoiceNumber = await storage.generateInvoiceNumber(repairCenterId);
        invoice = await storage.createInvoice({
          invoiceNumber,
          customerId,
          posTransactionId: transaction.id,
          repairCenterId,
          source: 'pos',
          amount: subtotal - discount,
          tax: taxAmount,
          total,
          paymentStatus: 'paid',
          paymentMethod,
          paidDate: new Date(),
          notes: `Fattura automatica da vendita POS ${transactionNumber}`,
        });
        await storage.updatePosTransactionInvoice(transaction.id, invoice.id);
      }

      // Auto RT submission for completed transactions (fire-and-forget)
      if (transaction.status === "completed") {
        attemptAutoRtSubmission(transaction.id, repairCenterId).catch(() => {});
      }

      res.json({ transaction, items: transactionItems, invoice });
    } catch (error: any) {
      console.error("Service order creation error:", error);
      console.error("POS transaction error:", error);
      res.status(500).json({ error: error.message });
    }
  });

