  // ==== STRIPE PAYMENT LINK FOR POS ====
  
  // Create Stripe Checkout Session for POS transaction (generates payment link)
  app.post("/api/repair-center/pos/create-payment-link", requireRole("repair_center", "repair_center_staff"), async (req, res) => {
    try {
      if (!req.user) return res.status(401).send("Unauthorized");
      
      const repairCenterId = req.user.repairCenterId;
      if (!repairCenterId) return res.status(400).send("Repair center not found");
      
      const { transactionId } = req.body;
      if (!transactionId) return res.status(400).json({ error: "Transaction ID required" });
      
      // Get transaction
      const transaction = await storage.getPosTransaction(transactionId);
      if (!transaction) return res.status(404).json({ error: "Transaction not found" });
      if (transaction.repairCenterId !== repairCenterId) return res.status(403).json({ error: "Not authorized" });
      if (transaction.status !== "pending") return res.status(400).json({ error: "Transaction must be pending" });
      
      // Get repair center and its payment config
      const repairCenter = await storage.getRepairCenter(repairCenterId);
      if (!repairCenter) return res.status(404).json({ error: "Repair center not found" });
      
      // Get payment config (from RC or parent reseller)
      let paymentConfig = await storage.getPaymentConfiguration('repair_center', repairCenterId);
      if (!paymentConfig || paymentConfig.useParentConfig) {
        if (repairCenter.resellerId) {
          paymentConfig = await storage.getPaymentConfiguration('reseller', repairCenter.resellerId);
        }
      }
      
      if (!paymentConfig?.stripeEnabled || !paymentConfig?.stripeSecretKey) {
        return res.status(400).json({ error: "Stripe not configured" });
      }
      
      // Decrypt Stripe secret key
      const stripeSecretDecrypted = decryptSecret(paymentConfig.stripeSecretKey);
      const stripe = new Stripe(stripeSecretDecrypted, { apiVersion: "2025-02-24.acacia" });
      
      // Get transaction items
      const items = await storage.getPosTransactionItems(transactionId);
      
      // Build line items for Stripe
      const lineItems = items.map(item => ({
        price_data: {
          currency: "eur",
          product_data: {
            name: item.productName,
            description: item.isService ? "Servizio" : (item.productSku || undefined),
          },
          unit_amount: item.unitPrice, // Already in cents
        },
        quantity: item.quantity,
      }));
      
      // Create Checkout Session
      const baseUrl = process.env.REPLIT_DOMAINS?.split(',')[0] 
        ? `https://${process.env.REPLIT_DOMAINS.split(',')[0]}`
        : 'http://localhost:5000';
      
      const session = await stripe.checkout.sessions.create({
        payment_method_types: ["card"],
        line_items: lineItems,
        mode: "payment",
        success_url: `${baseUrl}/pos-payment-success?session_id={CHECKOUT_SESSION_ID}&transaction_id=${transactionId}`,
        cancel_url: `${baseUrl}/pos-payment-cancel?transaction_id=${transactionId}`,
        expires_at: Math.floor(Date.now() / 1000) + (24 * 60 * 60), // 24 hours
        metadata: {
          transactionId,
          repairCenterId,
          type: "pos_payment",
        },
      });
      
      // Update transaction with Stripe session info
      await storage.updatePosTransaction(transactionId, {
        stripeSessionId: session.id,
        stripePaymentUrl: session.url,
        stripePaymentExpiresAt: new Date(session.expires_at * 1000),
      });
      
      res.json({
        paymentUrl: session.url,
        sessionId: session.id,
        expiresAt: new Date(session.expires_at * 1000).toISOString(),
      });
    } catch (error: any) {
      console.error("POS Payment Link error:", error);
      res.status(500).json({ error: error.message });
    }
  });

  // PayPal Payment Link for POS (Repair Center)
  app.post("/api/repair-center/pos/create-paypal-order", requireRole("repair_center", "repair_center_staff"), async (req, res) => {
    try {
      if (!req.user) return res.status(401).send("Unauthorized");
      
      const repairCenterId = req.user.repairCenterId;
      if (!repairCenterId) return res.status(400).send("Repair center not found");
      
      const { transactionId } = req.body;
      if (!transactionId) return res.status(400).json({ error: "Transaction ID required" });
      
      // Get transaction
      const transaction = await storage.getPosTransaction(transactionId);
      if (!transaction) return res.status(404).json({ error: "Transaction not found" });
      if (transaction.repairCenterId !== repairCenterId) return res.status(403).json({ error: "Not authorized" });
      if (transaction.status !== "pending") return res.status(400).json({ error: "Transaction must be pending" });
      
      // Get repair center and its payment config
      const repairCenter = await storage.getRepairCenter(repairCenterId);
      if (!repairCenter) return res.status(404).json({ error: "Repair center not found" });
      
      // Get payment config (from RC or parent reseller)
      let paymentConfig = await storage.getPaymentConfiguration('repair_center', repairCenterId);
      if (!paymentConfig || paymentConfig.useParentConfig) {
        if (repairCenter.resellerId) {
          paymentConfig = await storage.getPaymentConfiguration('reseller', repairCenter.resellerId);
        }
      }
      
      if (!paymentConfig?.paypalEnabled || !paymentConfig?.paypalClientId || !paymentConfig?.paypalClientSecret) {
        return res.status(400).json({ error: "PayPal not configured" });
      }
      
      // Decrypt PayPal secret
      const decryptedSecret = decryptSecret(paymentConfig.paypalClientSecret);
      
      // Calculate amount in EUR (from cents to decimal string)
      const amount = (transaction.total / 100).toFixed(2);
      
      // Build return/cancel URLs
      const baseUrl = process.env.REPLIT_DOMAINS?.split(',')[0] 
        ? `https://${process.env.REPLIT_DOMAINS.split(',')[0]}`
        : 'http://localhost:5000';
      
      const returnUrl = `${baseUrl}/pos-payment-success?transaction_id=${transactionId}&type=paypal`;
      const cancelUrl = `${baseUrl}/pos-payment-cancel?transaction_id=${transactionId}`;
      
      // Create PayPal order
      const result = await createPayPalOrderHandler(
        paymentConfig.paypalClientId,
        decryptedSecret,
        amount,
        "EUR",
        "CAPTURE",
        returnUrl,
        cancelUrl
      );
      
      // Find approval URL from PayPal response
      const approvalLink = result.body.links?.find((l: any) => l.rel === "payer-action" || l.rel === "approve");
      const approvalUrl = approvalLink?.href || null;
      
      // Update transaction with PayPal order info
      await storage.updatePosTransaction(transactionId, {
        paypalOrderId: result.body.id,
        paypalApprovalUrl: approvalUrl,
      });
      
      res.json({
        orderId: result.body.id,
        approvalUrl: approvalUrl,
      });
    } catch (error: any) {
      console.error("POS PayPal order error:", error);
      res.status(500).json({ error: error.message });
    }
  });

  // Check PayPal payment status for POS transaction
  app.get("/api/repair-center/pos/check-paypal-status/:transactionId", requireRole("repair_center", "repair_center_staff"), async (req, res) => {
    try {
      if (!req.user) return res.status(401).send("Unauthorized");
      
      const repairCenterId = req.user.repairCenterId;
      if (!repairCenterId) return res.status(400).send("Repair center not found");
      
      const { transactionId } = req.params;
      
      // Get transaction
      const transaction = await storage.getPosTransaction(transactionId);
      if (!transaction) return res.status(404).json({ error: "Transaction not found" });
      if (transaction.repairCenterId !== repairCenterId) return res.status(403).json({ error: "Not authorized" });
      
      // If already completed, return status
      if (transaction.status === "completed") {
        return res.json({ status: "completed", paid: true });
      }
      
      // If no PayPal order, return pending
      if (!transaction.paypalOrderId) {
        return res.json({ status: "pending", paid: false, approvalUrl: transaction.paypalApprovalUrl });
      }
      
      // Get payment config
      const repairCenter = await storage.getRepairCenter(repairCenterId);
      let paymentConfig = await storage.getPaymentConfiguration('repair_center', repairCenterId);
      if (!paymentConfig || paymentConfig.useParentConfig) {
        if (repairCenter?.resellerId) {
          paymentConfig = await storage.getPaymentConfiguration('reseller', repairCenter.resellerId);
        }
      }
      
      if (!paymentConfig?.paypalClientId || !paymentConfig?.paypalClientSecret) {
        return res.status(400).json({ error: "PayPal not configured" });
      }
      
      // First check order status before attempting capture
      const decryptedSecret = decryptSecret(paymentConfig.paypalClientSecret);
      console.log("Checking PayPal order status for:", transaction.paypalOrderId);
      try {
        const orderStatus = await getPayPalOrderStatus(
          paymentConfig.paypalClientId,
          decryptedSecret,
          transaction.paypalOrderId
        );
        console.log("PayPal order status result:", orderStatus);
        
        // If already completed, update transaction
        if (orderStatus.status === "COMPLETED") {
          if (transaction.status === "pending") {
            await storage.updatePosTransaction(transactionId, { 
              status: "completed",
              paymentReference: orderStatus.id
            });
            
            if (transaction.sessionId) {
              const sessionData = await storage.getPosSession(transaction.sessionId);
              if (sessionData) {
                await storage.updatePosSessionTotals(transaction.sessionId, {
                  totalSales: (sessionData.totalSales || 0) + transaction.total,
                  totalTransactions: (sessionData.totalTransactions || 0) + 1,
                  totalCardSales: (sessionData.totalCardSales || 0) + transaction.total,
                });
              }
            }
          }
          // Auto RT submission
          attemptAutoRtSubmission(transactionId, repairCenterId).catch(() => {});
          return res.json({ status: "completed", paid: true });
        }
        
        // If approved, capture the payment
        if (orderStatus.status === "APPROVED") {
          const captureResult = await capturePayPalOrderHandler(
            paymentConfig.paypalClientId,
            decryptedSecret,
            transaction.paypalOrderId
          );
          
          if (captureResult.body.status === "COMPLETED") {
            await storage.updatePosTransaction(transactionId, { 
              status: "completed",
              paymentReference: captureResult.body.id
            });
            
            if (transaction.sessionId) {
              const sessionData = await storage.getPosSession(transaction.sessionId);
              if (sessionData) {
                await storage.updatePosSessionTotals(transaction.sessionId, {
                  totalSales: (sessionData.totalSales || 0) + transaction.total,
                  totalTransactions: (sessionData.totalTransactions || 0) + 1,
                  totalCardSales: (sessionData.totalCardSales || 0) + transaction.total,
                });
              }
            }
            // Auto RT submission
            attemptAutoRtSubmission(transactionId, repairCenterId).catch(() => {});
            return res.json({ status: "completed", paid: true });
          }
        }
        
        // Still pending
        return res.json({ status: "pending", paid: false, approvalUrl: transaction.paypalApprovalUrl });
      } catch (checkError: any) {
        console.error("PayPal check error:", checkError);
        return res.json({ status: "pending", paid: false, approvalUrl: transaction.paypalApprovalUrl });
      }
    } catch (error: any) {
      console.error("POS PayPal status error:", error);
      res.status(500).json({ error: error.message });
    }
  });
  
  // Check payment status for POS transaction
  app.get("/api/repair-center/pos/check-payment-status/:transactionId", requireRole("repair_center", "repair_center_staff"), async (req, res) => {
    try {
      if (!req.user) return res.status(401).send("Unauthorized");
      
      const repairCenterId = req.user.repairCenterId;
      if (!repairCenterId) return res.status(400).send("Repair center not found");
      
      const { transactionId } = req.params;
      
      // Get transaction
      const transaction = await storage.getPosTransaction(transactionId);
      if (!transaction) return res.status(404).json({ error: "Transaction not found" });
      if (transaction.repairCenterId !== repairCenterId) return res.status(403).json({ error: "Not authorized" });
      
      // If already completed or expired, return current status
      if (transaction.status !== "pending") {
        return res.json({ status: transaction.status, paymentUrl: transaction.stripePaymentUrl });
      }
      
      // Check if link expired
      if (transaction.stripePaymentExpiresAt && new Date(transaction.stripePaymentExpiresAt) < new Date()) {
        await storage.updatePosTransaction(transactionId, { status: "expired" });
        return res.json({ status: "expired", paymentUrl: null });
      }
      
      // Check Stripe session status
      if (!transaction.stripeSessionId) {
        return res.json({ status: "pending", paymentUrl: transaction.stripePaymentUrl });
      }
      
      // Get payment config
      const repairCenter = await storage.getRepairCenter(repairCenterId);
      let paymentConfig = await storage.getPaymentConfiguration('repair_center', repairCenterId);
      if (!paymentConfig || paymentConfig.useParentConfig) {
        if (repairCenter?.resellerId) {
          paymentConfig = await storage.getPaymentConfiguration('reseller', repairCenter.resellerId);
        }
      }
      
      if (!paymentConfig?.stripeSecretKey) {
        return res.status(400).json({ error: "Stripe not configured" });
      }
      
      const stripeSecretDecrypted = decryptSecret(paymentConfig.stripeSecretKey);
      const stripe = new Stripe(stripeSecretDecrypted, { apiVersion: "2025-02-24.acacia" });
      
      // Retrieve session from Stripe
      const session = await stripe.checkout.sessions.retrieve(transaction.stripeSessionId);
      
      if (session.payment_status === "paid" && transaction.status === "pending") {
        // Payment completed - update transaction
        await storage.updatePosTransaction(transactionId, { 
          status: "completed",
          paymentReference: session.payment_intent as string,
        });
        
        // Update session totals if there's a session
        if (transaction.sessionId) {
          const sessionData = await storage.getPosSession(transaction.sessionId);
          if (sessionData) {
            await storage.updatePosSessionTotals(transaction.sessionId, {
              totalSales: (sessionData.totalSales || 0) + transaction.total,
              totalCard: (sessionData.totalCard || 0) + transaction.total,
              transactionCount: (sessionData.transactionCount || 0) + 1,
            });
          }
        }
        
        // Auto RT submission
        attemptAutoRtSubmission(transactionId, repairCenterId).catch(() => {});

        return res.json({ status: "completed", paymentUrl: null });
      } else if (session.status === "expired") {
        await storage.updatePosTransaction(transactionId, { status: "expired" });
        return res.json({ status: "expired", paymentUrl: null });
      }
      
      return res.json({ status: "pending", paymentUrl: transaction.stripePaymentUrl });
    } catch (error: any) {
      console.error("POS Check Payment Status error:", error);
      res.status(500).json({ error: error.message });
    }
  });
  
