  // ==========================================
  // RESELLER POS TERMINAL ENDPOINTS
  // ==========================================
  
  // Crea transazione POS per conto di un centro riparazione
  app.post("/api/reseller/pos/transaction", requireRole("reseller", "reseller_staff", "sub_reseller"), async (req, res) => {
    try {
      const { resellerId } = getEffectiveContext(req);
      const operatorId = req.user!.id;
      const { repairCenterId, registerId, items, paymentMethod, customerId, discountAmount, discountPercent, cashReceived, notes, customerNotes, invoiceRequested, lotteryCode, documentType } = req.body;
      
      if (!repairCenterId) return res.status(400).json({ error: "repairCenterId è obbligatorio" });
      
      // Verifica ownership del centro riparazione
      const center = await storage.getRepairCenter(repairCenterId);
      if (!center || center.resellerId !== resellerId) {
        return res.status(403).json({ error: "Non autorizzato ad operare su questo centro riparazione" });
      }
      
      // Verifica che il registro appartenga al centro
      if (registerId) {
        const register = await storage.getPosRegister(registerId);
        if (!register || register.repairCenterId !== repairCenterId) {
          return res.status(403).json({ error: "Cassa non appartenente a questo centro riparazione" });
        }
      }
      
      const session = await storage.getOpenPosSession(repairCenterId, registerId);
      if (!session) return res.status(400).json({ error: "Nessuna sessione cassa aperta per questa cassa." });

      if (!items || items.length === 0) return res.status(400).json({ error: "Nessun articolo" });
      if (!paymentMethod) return res.status(400).json({ error: "Metodo pagamento richiesto" });

      if (lotteryCode && (typeof lotteryCode !== "string" || !/^[A-Za-z0-9]{8}$/.test(lotteryCode))) {
        return res.status(400).json({ error: "Codice lotteria non valido (8 caratteri alfanumerici)" });
      }

      // Trova il magazzino del repair center
      const warehouseList = await storage.listWarehouses({ 
        ownerType: 'repair_center', 
        ownerId: repairCenterId 
      });
      const repairCenterWarehouseId = warehouseList.length > 0 ? warehouseList[0].id : null;

      let subtotal = 0;
      const processedItems = [];
      
      for (const item of items) {
        if (item.isTemporary) {
          if (!item.productName || typeof item.unitPrice !== 'number') {
            return res.status(400).json({ error: "Prodotto temporaneo richiede nome e prezzo" });
          }
          const itemDiscount = item.discount || 0;
          const totalPrice = (item.unitPrice * item.quantity) - itemDiscount;
          
          processedItems.push({
            productId: null,
            productName: item.productName,
            productSku: null,
            productBarcode: null,
            isTemporary: true,
            quantity: item.quantity,
            unitPrice: item.unitPrice,
            discount: itemDiscount,
            totalPrice,
            vatRate: typeof item.vatRate === 'number' ? item.vatRate : 22,
            warehouseId: null,
          });
          
          subtotal += totalPrice;
          continue;
        }
        
        if (item.isService) {
          if (!item.serviceItemId) {
            return res.status(400).json({ error: "Servizio richiede serviceItemId" });
          }
          const serviceItem = await storage.getServiceItem(item.serviceItemId);
          if (!serviceItem) return res.status(400).json({ error: `Servizio ${item.serviceItemId} non trovato` });
          
          const unitPrice = item.unitPrice ?? serviceItem.defaultPriceCents;
          const itemDiscount = item.discount || 0;
          const totalPrice = (unitPrice * item.quantity) - itemDiscount;
          
          processedItems.push({
            productId: null,
            productName: serviceItem.name,
            productSku: serviceItem.code,
            productBarcode: null,
            serviceItemId: item.serviceItemId,
            isService: true,
            isTemporary: false,
            quantity: item.quantity,
            unitPrice: unitPrice,
            discount: itemDiscount,
            totalPrice,
            vatRate: typeof item.vatRate === 'number' ? item.vatRate : ((serviceItem as any).vatRate ?? 22),
            warehouseId: null,
          });
          
          subtotal += totalPrice;
          continue;
        }
        
        if (item.isWarranty) {
          if (!item.warrantyProductId) {
            return res.status(400).json({ error: "Garanzia richiede warrantyProductId" });
          }
          const warrantyProduct = await storage.getWarrantyProduct(item.warrantyProductId);
          if (!warrantyProduct) return res.status(400).json({ error: `Prodotto garanzia ${item.warrantyProductId} non trovato` });
          
          const unitPrice = item.unitPrice ?? warrantyProduct.priceInCents;
          const itemDiscount = item.discount || 0;
          const totalPrice = (unitPrice * item.quantity) - itemDiscount;
          
          processedItems.push({
            productId: null,
            productName: warrantyProduct.name,
            productSku: null,
            productBarcode: null,
            warrantyProductId: item.warrantyProductId,
            isWarranty: true,
            isService: false,
            isTemporary: false,
            quantity: item.quantity,
            unitPrice: unitPrice,
            discount: itemDiscount,
            totalPrice,
            vatRate: typeof item.vatRate === 'number' ? item.vatRate : 22,
            warehouseId: null,
          });
          
          subtotal += totalPrice;
          continue;
        }
        
        const product = await storage.getProduct(item.productId);
        if (!product) return res.status(400).json({ error: `Prodotto ${item.productId} non trovato` });
        
        const unitPrice = item.unitPrice || (product.unitPrice || 0);
        const itemDiscount = item.discount || 0;
        const totalPrice = (unitPrice * item.quantity) - itemDiscount;
        
        processedItems.push({
          productId: item.productId,
          productName: product.name,
          productSku: product.sku || null,
          productBarcode: product.barcode || null,
          isTemporary: false,
          quantity: item.quantity,
          unitPrice: unitPrice,
          discount: itemDiscount,
          totalPrice,
          vatRate: typeof item.vatRate === 'number' ? item.vatRate : ((product as any).vatRate ?? 22),
          warehouseId: repairCenterWarehouseId,
        });
        
        subtotal += totalPrice;
      }

      const discount = discountAmount || (discountPercent ? Math.round(subtotal * discountPercent / 100) : 0);
      const taxableAmount = subtotal - discount;
      // Calcolo IVA multi-aliquota: prezzi netti + IVA in avanti
      let taxAmount = 0;
      let weightedTaxRate = 0;
      if (processedItems.length > 0 && taxableAmount > 0) {
        const discountRatio = subtotal > 0 ? taxableAmount / subtotal : 1;
        for (const pi of processedItems) {
          const adjustedItemTotal = Math.round(pi.totalPrice * discountRatio);
          const itemVat = pi.vatRate ?? 22;
          taxAmount += Math.round(adjustedItemTotal * itemVat / 100);
        }
        weightedTaxRate = taxableAmount > 0 ? Math.round(taxAmount / taxableAmount * 100 * 100) / 100 : 22;
      }
      const taxRate = weightedTaxRate || 22;
      const total = taxableAmount + taxAmount;

      const transactionNumber = await storage.generatePosTransactionNumber(repairCenterId);
      const dailyNumber = await storage.generatePosDailyNumber(repairCenterId, session.registerId || null);
      let changeGiven = null;
      if (paymentMethod === "cash" && cashReceived) changeGiven = cashReceived - total;

      const transaction = await storage.createPosTransaction({
        transactionNumber,
        repairCenterId,
        sessionId: session.id,
        registerId: session.registerId || null,
        customerId: customerId || null,
        operatorId,
        subtotal,
        discountAmount: discount,
        discountPercent: discountPercent || null,
        taxRate,
        taxAmount,
        total,
        paymentMethod,
        cashReceived: cashReceived || null,
        changeGiven,
        lotteryCode: lotteryCode || null,
        documentType: documentType || (invoiceRequested ? 'invoice' : 'receipt'),
        dailyNumber,
        notes: notes || null,
        customerNotes: customerNotes || null,
        invoiceRequested: invoiceRequested || false,
        status: (paymentMethod === "stripe_link" || paymentMethod === "paypal") ? "pending" : "completed",
      });

      const transactionItems = await storage.createPosTransactionItems(
        processedItems.map(item => ({ transactionId: transaction.id, ...item, inventoryDeducted: false }))
      );
      
      for (const item of transactionItems) {
        if (item.warehouseId && item.productId && item.quantity > 0 && !item.isTemporary) {
          await storage.updateWarehouseStockQuantity(item.warehouseId, item.productId, -item.quantity);
          await storage.markPosItemInventoryDeducted(item.id);
        }
      }

      // Auto-create warranty records for warranty items sold to registered customers
      if (customerId) {
        for (const item of transactionItems) {
          if (item.isWarranty && item.warrantyProductId) {
            try {
              const wp = await storage.getWarrantyProduct(item.warrantyProductId);
              if (wp) {
                const startsAt = new Date();
                const endsAt = new Date();
                endsAt.setMonth(endsAt.getMonth() + wp.durationMonths);
                await storage.createRepairWarranty({
                  repairOrderId: null,
                  customerId,
                  warrantyProductId: wp.id,
                  sellerType: 'reseller',
                  sellerId: resellerId,
                  status: 'accepted',
                  priceSnapshot: item.unitPrice,
                  durationMonthsSnapshot: wp.durationMonths,
                  coverageTypeSnapshot: wp.coverageType,
                  productNameSnapshot: wp.name,
                  startsAt,
                  endsAt,
                });
              }
            } catch (e) {
              console.error('Auto warranty creation error:', e);
            }
          }
        }
      }
      
      const sessionTxs = await storage.getPosTransactionsBySession(session.id);
      const completedTxs = sessionTxs.filter(t => t.status === "completed");
      await storage.updatePosSessionTotals(session.id, {
        totalSales: completedTxs.reduce((sum, t) => sum + t.total, 0),
        totalTransactions: completedTxs.length,
        totalCashSales: completedTxs.filter(t => t.paymentMethod === "cash").reduce((sum, t) => sum + t.total, 0),
        totalCardSales: completedTxs.filter(t => t.paymentMethod !== "cash").reduce((sum, t) => sum + t.total, 0),
      });

      let invoice = null;
      if (invoiceRequested && customerId) {
        const invoiceNumber = await storage.generateInvoiceNumber(repairCenterId);
        invoice = await storage.createInvoice({
          invoiceNumber,
          customerId,
          posTransactionId: transaction.id,
          repairCenterId,
          source: 'pos',
          amount: subtotal - discount,
          tax: taxAmount,
          total,
          paymentStatus: 'paid',
          paymentMethod,
          paidDate: new Date(),
          notes: `Fattura automatica da vendita POS ${transactionNumber}`,
        });
        await storage.updatePosTransactionInvoice(transaction.id, invoice.id);
      }

      // Auto RT submission for completed transactions (fire-and-forget)
      if (transaction.status === "completed") {
        attemptAutoRtSubmission(transaction.id, repairCenterId).catch(() => {});
      }

      res.json({ transaction, items: transactionItems, invoice });
    } catch (error: any) {
      console.error("Service order creation error:", error);
      console.error("Reseller POS transaction error:", error);
      res.status(500).json({ error: error.message });
    }
  });

  // Lista prodotti di un centro riparazione (per POS terminal reseller)
  app.get("/api/reseller/pos/:repairCenterId/products", requireRole("reseller", "reseller_staff", "sub_reseller"), async (req, res) => {
    try {
      const { resellerId } = getEffectiveContext(req);
      const { repairCenterId } = req.params;
      const search = req.query.search as string | undefined;
      const priceListId = req.query.priceListId as string | undefined;
      
      const center = await storage.getRepairCenter(repairCenterId);
      if (!center || center.resellerId !== resellerId) {
        return res.status(403).json({ error: "Non autorizzato" });
      }
      
      // Cerca magazzino del centro
      const warehouseList = await storage.listWarehouses({ 
        ownerType: 'repair_center', 
        ownerId: repairCenterId 
      });
      
      if (warehouseList.length === 0) {
        return res.json([]);
      }
      
      const warehouse = warehouseList[0];
      const productsWithStock = await storage.listWarehouseProductsWithStock(warehouse.id, search);
      
      // Se è specificato un priceListId, usa quello direttamente
      if (priceListId) {
        const priceList = await storage.getPriceList(priceListId);
        if (priceList) {
          const priceListItems = await storage.listPriceListItems(priceList.id);
          
          const priceMap = new Map<string, number>();
          const vatRateMap = new Map<string, number>();
          const defaultVatRate = (priceList as any).defaultVatRate ?? 22;
          for (const item of priceListItems) {
            if (item.productId && item.isActive) {
              priceMap.set(item.productId, item.priceCents);
              vatRateMap.set(item.productId, (item as any).vatRate ?? defaultVatRate);
            }
          }
          
          const productsWithListPrice = productsWithStock.map(product => ({
            ...product,
            listPrice: priceMap.get(product.id) ?? null,
            priceListName: priceMap.has(product.id) ? priceList.name : null,
            vatRate: vatRateMap.get(product.id) ?? defaultVatRate,
          }));
          
          return res.json(productsWithListPrice);
        }
      }
      
      // Fallback: usa il primo listino ereditato disponibile
      const inheritedLists = await storage.getInheritedPriceLists(repairCenterId, 'repair_center');
      
      if (inheritedLists.length > 0) {
        const priceList = inheritedLists[0];
        const priceListItems = await storage.listPriceListItems(priceList.id);
        
        const priceMap = new Map<string, number>();
          const vatRateMap = new Map<string, number>();
          const defaultVatRate = (priceList as any).defaultVatRate ?? 22;
        for (const item of priceListItems) {
          if (item.productId && item.isActive) {
            priceMap.set(item.productId, item.priceCents);
              vatRateMap.set(item.productId, (item as any).vatRate ?? defaultVatRate);
          }
        }
        
        const productsWithListPrice = productsWithStock.map(product => ({
          ...product,
          listPrice: priceMap.get(product.id) ?? null,
          priceListName: priceMap.has(product.id) ? priceList.name : null,
            vatRate: vatRateMap.get(product.id) ?? defaultVatRate,
        }));
        
        return res.json(productsWithListPrice);
      }
      
      res.json(productsWithStock);
    } catch (error: any) {
      console.error("Service order creation error:", error);
      res.status(500).json({ error: error.message });
    }
  });

  // Lista servizi per POS terminal reseller
  app.get("/api/reseller/pos/:repairCenterId/services", requireRole("reseller", "reseller_staff", "sub_reseller"), async (req, res) => {
    try {
      const { resellerId } = getEffectiveContext(req);
      const { repairCenterId } = req.params;
      const search = req.query.search as string | undefined;
      const category = req.query.category as string | undefined;
      const priceListId = req.query.priceListId as string | undefined;
      
      const center = await storage.getRepairCenter(repairCenterId);
      if (!center || center.resellerId !== resellerId) {
        return res.status(403).json({ error: "Non autorizzato" });
      }
      
      // Prendi tutti i servizi e filtra per reseller
      const items = await storage.listServiceItems();
      let activeItems = items.filter(item => 
        item.isActive && (
          !item.resellerId || 
          item.resellerId === resellerId
        )
      );
      
      if (search) {
        const searchLower = search.toLowerCase();
        activeItems = activeItems.filter(item =>
          item.name.toLowerCase().includes(searchLower) ||
          (item.description && item.description.toLowerCase().includes(searchLower))
        );
      }
      
      if (category) {
        activeItems = activeItems.filter(item => item.category === category);
      }
      
      // Se è specificato un priceListId, usa i prezzi dal listino
      if (priceListId) {
        const priceList = await storage.getPriceList(priceListId);
        if (priceList) {
          const priceListItems = await storage.listPriceListItems(priceList.id);
          const defaultVatRate = (priceList as any).defaultVatRate ?? 22;
          
          const priceMap = new Map<string, number>();
          const vatRateMap = new Map<string, number>();
          for (const pli of priceListItems) {
            if (pli.serviceItemId && pli.isActive) {
              priceMap.set(pli.serviceItemId, pli.priceCents);
              vatRateMap.set(pli.serviceItemId, (pli as any).vatRate ?? defaultVatRate);
            }
          }
          
          const servicesWithListPrice = activeItems.map(item => ({
            id: item.id,
            code: item.code,
            name: item.name,
            description: item.description,
            category: item.category,
            priceCents: priceMap.get(item.id) ?? item.defaultPriceCents,
            laborMinutes: item.defaultLaborMinutes,
            vatRate: vatRateMap.get(item.id) ?? defaultVatRate,
            priceListName: priceMap.has(item.id) ? priceList.name : null,
          }));
          
          return res.json(servicesWithListPrice);
        }
      }
      
      // Fallback: Recupera prezzi personalizzati del centro e del reseller
      const centerPrices = await storage.listServiceItemPricesByRepairCenter(repairCenterId);
      const resellerPrices = await storage.listServiceItemPricesByReseller(resellerId);
      
      // Mappa i servizi con prezzi effettivi
      const servicesWithPrices = activeItems.map(item => {
        const centerPrice = centerPrices.find(p => p.serviceItemId === item.id);
        const resellerPrice = resellerPrices.find(p => p.serviceItemId === item.id);
        const effectivePrice = centerPrice?.priceCents ?? resellerPrice?.priceCents ?? item.defaultPriceCents;
        
        return {
          id: item.id,
          code: item.code,
          name: item.name,
          description: item.description,
          category: item.category,
          priceCents: effectivePrice,
          laborMinutes: centerPrice?.laborMinutes ?? resellerPrice?.laborMinutes ?? item.defaultLaborMinutes,
          vatRate: 22,
        };
      });
      
      res.json(servicesWithPrices);
    } catch (error: any) {
      console.error("Service order creation error:", error);
      res.status(500).json({ error: error.message });
    }
  });
  // Warranty products per POS (prodotti garanzia vendibili in cassa)
  app.get("/api/reseller/pos/:repairCenterId/warranty-products", requireRole("reseller", "reseller_staff", "sub_reseller"), async (req, res) => {
    try {
      const { resellerId } = getEffectiveContext(req);
      const { repairCenterId } = req.params;
      const center = await storage.getRepairCenter(repairCenterId);
      if (!center || center.resellerId !== resellerId) {
        return res.status(403).json({ error: "Non autorizzato" });
      }
      const warrantyProds = await storage.listWarrantyProductsByReseller(resellerId, true);
      const activeWarranties = warrantyProds.filter(p => p.isActive);

      const priceListId = req.query.priceListId as string | undefined;
      if (priceListId) {
        const inheritedLists = await storage.getInheritedPriceLists(repairCenterId, 'repair_center');
        const isAccessible = inheritedLists.some(pl => pl.id === priceListId);
        if (!isAccessible) {
          return res.status(403).json({ error: "Price list not accessible" });
        }
        const priceList = await storage.getPriceList(priceListId);
        if (priceList) {
          const priceListItems = await storage.listPriceListItems(priceList.id);
          const defaultVatRate = (priceList as any).defaultVatRate ?? 22;
          const priceMap = new Map<string, { priceCents: number; vatRate: number }>();
          for (const pli of priceListItems) {
            if (pli.warrantyProductId && pli.isActive) {
              priceMap.set(pli.warrantyProductId, {
                priceCents: pli.priceCents,
                vatRate: (pli as any).vatRate ?? defaultVatRate,
              });
            }
          }
          const withListPrice = activeWarranties.map(wp => {
            const override = priceMap.get(wp.id);
            return {
              ...wp,
              priceInCents: override ? override.priceCents : wp.priceInCents,
              vatRate: override ? override.vatRate : defaultVatRate,
              priceListName: override ? priceList.name : null,
            };
          });
          return res.json(withListPrice);
        }
      }

      res.json(activeWarranties);
    } catch (error) {
      console.error("POS warranty products error:", error);
      res.status(500).json({ error: "Errore caricamento prodotti garanzia" });
    }
  });

